                      if (e.name) return <p key={j} style={{ fontSize: "0.75rem", color: "var(--color-text)", opacity: 0.85, margin: "0.2rem 0" }}><strong>{e.name}:</strong> {typeof e.entry === "string" ? e.entry : ""}</p>;
                      return null;
                    })}
