      flex: 1,
      fontSize: "0.82rem",
      fontWeight: 700,
    },
    dismissBtn: {
      background: "none",
      border: "none",
      cursor: "pointer",
      padding: "2px",
      borderRadius: "3px",
      color: "var(--color-muted)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      flexShrink: 0,
      opacity: 0.6,
      transition: "opacity 0.15s",
    },
    cardBody: {
      fontSize: "0.8rem",
      color: "var(--color-text)",
      lineHeight: 1.45,
      whiteSpace: "pre-wrap",
      wordBreak: "break-word",
      cursor: "inherit",
    },
    expandToggle: {
      color: "var(--color-muted)",
      fontWeight: 600,
      cursor: "pointer",
      marginLeft: "4px",
      fontSize: "0.75rem",
    },
    footer: {
      padding: "10px 16px",
      borderTop: "1px solid rgba(255, 255, 255, 0.05)",
      flexShrink: 0,
    },
    checkBtn: {
      width: "100%",
      padding: "8px",
      borderRadius: "6px",
      background: "rgba(200, 151, 58, 0.1)",
      border: "1px solid rgba(200, 151, 58, 0.25)",
      color: "var(--color-accent)",
      fontSize: "0.78rem",
      fontWeight: 600,
      cursor: "pointer",
      transition: "background 0.15s",
    },
  };

  return (
    <div style={styles.container}>
      {/* Header */}
      <div style={styles.header}>
        <div style={styles.headerLeft}>
          <BrainCircuit size={20} color="var(--color-accent)" />
          <div style={styles.headerTitles}>
            <div style={styles.headerTitle}>AI Co-Pilot</div>
            <div style={styles.headerSubtitle}>Proactive DM Assistant</div>
          </div>
        </div>
        <div
          style={{
            ...styles.statusDot,
            background: socket?.connected ? "#22c55e" : "#ef4444",
            boxShadow: socket?.connected
              ? "0 0 6px rgba(34, 197, 94, 0.6)"
              : "0 0 6px rgba(239, 68, 68, 0.4)",
          }}
          aria-label={socket?.connected ? "Connected" : "Disconnected"}
        />
      </div>

      {/* Cooldown Banner */}
      {isCooldown && (
        <div style={styles.cooldownBanner}>Cooldown active</div>
      )}

      {/* Suggestions */}
      <div style={styles.scrollArea}>
        {suggestions.length === 0 ? (
          <div style={styles.emptyState}>
            <div style={styles.emptyIcon}>
              <BrainCircuit size={24} opacity={0.4} />
            </div>
            <div>Co-Pilot is monitoring the session</div>
          </div>
        ) : (
          suggestions.map((s) => {
            const colors = PRIORITY_COLORS[s.priority] || PRIORITY_COLORS.low;
            const icon = TYPE_ICONS[s.type] || DEFAULT_ICON;
            const isExpanded = expandedIds.has(s.id);
            const needsTruncation = s.text && s.text.length > 150;

            return (
              <div
                key={s.id}
                style={{
                  ...styles.card,
                  background: colors.bg,
                  borderColor: colors.border,
                }}
              >
                <div style={styles.cardHeader}>
                  <span style={styles.cardIcon}>{icon}</span>
                  <span
                    style={{
                      ...styles.cardTitle,
                      color: colors.label,
                    }}
                  >
                    {s.title}
                  </span>
                  <button
                    onClick={() => dismiss(s.id)}
                    style={styles.dismissBtn}
                    aria-label="Dismiss"
                    className="touch-target"
                    onMouseEnter={(e) => (e.currentTarget.style.opacity = "1")}
                    onMouseLeave={(e) => (e.currentTarget.style.opacity = "0.6")}
                  >
                    <X size={14} />
                  </button>
                </div>
                <div
                  style={styles.cardBody}
                  onClick={() => {
                    if (needsTruncation) toggleExpand(s.id);
                  }}
                >
                  {isExpanded || !needsTruncation
                    ? s.text
                    : `${s.text.slice(0, 150)}\u2026`}
                  {needsTruncation && (
                    <span style={styles.expandToggle}>
                      {isExpanded ? " Show less" : " Show more"}
                    </span>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Footer — Manual Check */}
      <div style={styles.footer}>
        <button
          onClick={handleCheckChat}
          style={{
            ...styles.checkBtn,
            opacity: socket?.connected ? 1 : 0.4,
          }}
          disabled={!socket?.connected}
          className="touch-target"
        >
          Check Current Chat
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
