export default function DiceRollerPanel({ user, isPopout = false }) {
  const { socket } = useSocket();
  const { rollDice } = useDiceBox();
  const [activeSubTab, setActiveSubTab] = useState(() => localStorage.getItem(DICE_ROLLER_TAB_STORAGE_KEY) || "roller"); // "roller" | "history"
  const [history, setHistory] = useState([]);
  const activeDiceTheme = getDiceThemeOption(user?.diceTheme || "default");
  const activeDiceColor = user?.diceColor || activeDiceTheme.defaultColor;
  const activeDiceStyle = getDiceThemePreviewStyles(activeDiceTheme.id, activeDiceColor);

  const [quantities, setQuantities] = useState({
    d4: 0,
    d6: 0,
    d8: 0,
    d10: 0,
    d12: 0,
    d20: 0,
    d100: 0,
  });
  const [modifier, setModifier] = useState(0);
  const [rollLabel, setRollLabel] = useState("");
  const [advantage, setAdvantage] = useState("normal"); // "normal" | "advantage" | "disadvantage"
  const [webGlSupported, setWebGlSupported] = useState(true);

  useEffect(() => {
    localStorage.setItem(DICE_ROLLER_TAB_STORAGE_KEY, activeSubTab);
  }, [activeSubTab]);

  useEffect(() => {
    setWebGlSupported(checkWebGLSupport());
  }, []);

  // Fetch initial roll history from database
  useEffect(() => {
    async function loadRollHistory() {
      try {
        const res = await fetch("/api/rolls");
        if (res.ok) {
          const data = await res.json();
          setHistory(data);
        }
      } catch (err) {
        console.error("Failed to load roll history:", err);
      }
    }
    loadRollHistory();
  }, []);

  // Real-time synchronization of shared roll history
  useEffect(() => {
    if (!socket) return;

    function handleIncomingRoll(msg) {
      if (msg.type === "roll" && msg.rollDetails) {
        const newRecord = {
          id: msg.id,
          sender: msg.sender,
          rollName: msg.rollDetails.rollName || "Dice Roll",
          formula: msg.rollDetails.formula || "",
          rolls: JSON.stringify(msg.rollDetails.rolls || []),
          modifier: msg.rollDetails.modifier || 0,
          total: msg.rollDetails.total || 0,
          diceTheme: msg.rollDetails.diceTheme || "default",
          diceColor: msg.rollDetails.diceColor || "#7c3aed",
          createdAt: new Date(msg.timestamp || Date.now()).toISOString(),
        };
        setHistory((prev) => {
          // Avoid duplicate appends
          if (prev.some((r) => r.id === newRecord.id)) return prev;
          return [newRecord, ...prev].slice(0, 50);
        });
      }
    }

    socket.on("chat:message", handleIncomingRoll);
    return () => {
      socket.off("chat:message", handleIncomingRoll);
    };
  }, [socket]);

  // Sender Name: Use the assigned character name (if any), fallback to username.
  const senderName = user?.characters?.[0]?.name || user?.username || "Anonymous";

  // Check if any dice are selected
  const hasDiceSelected = Object.values(quantities).some((qty) => qty > 0);
  const selectedDiceCount = Object.values(quantities).reduce((sum, qty) => sum + qty, 0);

  // Helper to change individual quantities
  const adjustQuantity = (dieId, amount) => {
    setQuantities((prev) => {
      const current = prev[dieId] || 0;
      const next = Math.max(0, current + amount);
      return { ...prev, [dieId]: next };
    });
  };

  // Helper to direct-tap increment
  const handleDieTap = (dieId) => {
    adjustQuantity(dieId, 1);
  };

  // Reset all fields
  const handleClear = () => {
    setQuantities({
      d4: 0,
      d6: 0,
      d8: 0,
      d10: 0,
      d12: 0,
      d20: 0,
      d100: 0,
    });
    setModifier(0);
    setRollLabel("");
    setAdvantage("normal");
  };

  // Handle D20 Advantage/Disadvantage options (auto-adds a d20 if count is 0)
  const handleAdvantageToggle = (mode) => {
    setAdvantage(mode);
    if (mode !== "normal" && quantities.d20 === 0) {
      setQuantities((prev) => ({ ...prev, d20: 1 }));
    }
  };

  // Build formula text on the fly
  const getFormulaPreview = () => {
    const parts = [];
    Object.entries(quantities).forEach(([key, qty]) => {
      if (qty > 0) {
        if (key === "d20" && advantage !== "normal" && qty === 1) {
          parts.push(`1d20 (${advantage === "advantage" ? "Adv" : "Disadv"})`);
        } else {
          parts.push(`${qty}${key}`);
        }
      }
    });

    if (parts.length === 0) return "Select dice to roll...";

    let formula = parts.join(" + ");
    if (modifier !== 0) {
      formula += modifier > 0 ? ` + ${modifier}` : ` - ${Math.abs(modifier)}`;
    }
    return formula;
  };

  // Execute Roll
  const handleRoll = async () => {
    if (!hasDiceSelected || !socket) return;

    const notation = [];
    const formulaParts = [];

    // Build notation from quantities
    Object.entries(quantities).forEach(([key, qty]) => {
      if (qty <= 0) return;
      const dieConfig = DICE_TYPES.find((d) => d.id === key);
      if (!dieConfig) return;
      const {sides} = dieConfig;

      if (key === "d20" && advantage !== "normal" && qty === 1) {
        // For advantage/disadvantage, roll two individual d20s
        notation.push("1d20", "1d20");
        const advLabel = advantage === "advantage" ? "Adv" : "Disadv";
        formulaParts.push(`1d20 (${advLabel})`);
      } else {
        notation.push(`${qty}${key}`);
        formulaParts.push(`${qty}${key}`);
      }
    });

    if (modifier !== 0) {
      formulaParts.push(modifier > 0 ? `+ ${modifier}` : `- ${Math.abs(modifier)}`);
    }

    const completedFormula = formulaParts.join(" ");

    // Roll via DiceBox (physics-based) or fallback
    let groups; let allRolls; let total;
    try {
      const result = await rollDice(notation, {
        theme: activeDiceTheme.id,
        color: activeDiceColor,
      });
      groups = result.groups;
      allRolls = result.allRolls;
      total = result.total;
    } catch (err) {
      console.error("[DiceRollerPanel] rollDice failed:", err);
      return;
    }

    // Handle advantage/disadvantage: the physics rolled two d20s;
    // we must pick the higher/lower and only count one.
    if (advantage !== "normal" && quantities.d20 === 1) {
      // groups will have 2 entries, each with a single d20 roll
      const roll1 = groups[0]?.rolls?.[0]?.value || 0;
      const roll2 = groups[1]?.rolls?.[0]?.value || 0;
      const chosen = advantage === "advantage" ? Math.max(roll1, roll2) : Math.min(roll1, roll2);
      const discarded = advantage === "advantage" ? Math.min(roll1, roll2) : Math.max(roll1, roll2);

      // Recompute total: only the chosen die contributes (plus modifier)
      total = chosen + modifier;

      // Rebuild allRolls: chosen d20 + preserve any other dice (e.g. 2d6 rolled alongside)
      const otherGroupRolls = [];
      for (let i = 2; i < groups.length; i++) {
        if (groups[i]?.rolls) {
          for (const die of groups[i].rolls) {
            otherGroupRolls.push(die.value);
          }
        }
      }
      allRolls = [chosen, ...otherGroupRolls];
    }

    const finalTotal = total;

    // Create descriptive summary text
    const descriptionText = `rolled ${getFormulaPreview()}! Total: ${finalTotal}`;

    // Emit to socket server (which will auto-write to the DB and broadcast)
    socket.emit("chat:send", {
      sender: senderName,
      text: descriptionText,
      type: "roll",
      rollDetails: {
        rollName: rollLabel.trim() || "Dice Roll",
        formula: completedFormula,
        rolls: allRolls,
        modifier,
        total: finalTotal,
        isAttack: false,
        status: "rolled",
        diceTheme: activeDiceTheme.id,
        diceColor: activeDiceColor,
      },
    });
  };

  const formulaPreview = getFormulaPreview();
  const rollButtonStyle = {
    ...styles.rollBtn,
    background: hasDiceSelected
      ? "linear-gradient(135deg, var(--color-accent) 0%, var(--color-accent-dark) 100%)"
      : "rgba(255, 255, 255, 0.04)",
    color: hasDiceSelected ? "var(--color-bg)" : "var(--color-muted)",
    boxShadow: hasDiceSelected ? "0 0 15px rgba(200, 151, 58, 0.45)" : "none",
  };

  const renderRollAction = () => (
    <>
      <div style={styles.formulaPreview}>
        <span style={styles.formulaLabel}>Formula Preview</span>
        <span style={styles.formulaText}>{formulaPreview}</span>
      </div>
      <button
        onClick={handleRoll}
        disabled={!hasDiceSelected}
        style={rollButtonStyle}
        className="touch-target btn-hover-scale"
      >
        <Dices size={18} />
        ROLL DICE
      </button>
    </>
  );

  return (
    <div style={styles.container} className={`dice-roller-shell ${isPopout ? "dice-roller-popout" : ""}`}>
      {/* Sub-tab Toggle Navigation */}
      <div style={styles.subTabNav} className="glass-panel">
        <button
          onClick={() => setActiveSubTab("roller")}
          style={{
            ...styles.subTabBtn,
            background: activeSubTab === "roller" ? "var(--color-accent-dim)" : "transparent",
            color: activeSubTab === "roller" ? "var(--color-accent)" : "var(--color-muted)",
            border: activeSubTab === "roller" ? "1px solid var(--color-border)" : "1px solid transparent",
          }}
          className="touch-target"
        >
          <Dices size={16} />
          Roll Dice
        </button>
        <button
          onClick={() => setActiveSubTab("history")}
          style={{
            ...styles.subTabBtn,
            background: activeSubTab === "history" ? "var(--color-accent-dim)" : "transparent",
            color: activeSubTab === "history" ? "var(--color-accent)" : "var(--color-muted)",
            border: activeSubTab === "history" ? "1px solid var(--color-border)" : "1px solid transparent",
          }}
          className="touch-target"
        >
          <History size={16} />
          Roll History
        </button>
        {!isPopout && user?.role === "DM" && (
          <button
            onClick={() => window.open("/#/dm/popout/dice", "_blank", "width=600,height=800,resizable=yes,scrollbars=yes")}
            style={{
              background: "none",
              border: "none",
              color: "var(--color-accent)",
              fontSize: "1.15rem",
              cursor: "pointer",
              marginLeft: "auto",
              paddingRight: "0.45rem",
              display: "flex",
              alignItems: "center",
              flexShrink: 0,
            }}
            className="touch-target btn-hover-scale"
            title="Pop out Dice Roller"
            aria-label="Pop out Dice Roller"
          >
            <ExternalLink size={17} />
          </button>
        )}
      </div>

      <div
        style={{
          ...styles.scrollWrapper,
          paddingBottom: activeSubTab === "roller" ? "130px" : "20px",
        }}
        className="dice-roller-scroll"
      >
        <div style={styles.content} className="dice-roller-content">
          {activeSubTab === "roller" ? (
            <div style={styles.rollerLayout} className="dice-roller-layout">
              <div style={styles.primaryColumn} className="dice-roller-primary">
                <div style={styles.headerRow}>
                  <div style={styles.headerTitleGroup}>
                    <h2 style={styles.title}>Dice Roller</h2>
                    <span
                      style={{
                        ...styles.statusBadge,
                        color: webGlSupported ? "var(--color-success)" : "var(--color-danger)",
                        background: webGlSupported ? "rgba(111, 207, 151, 0.1)" : "rgba(235, 87, 87, 0.1)",
                        border: webGlSupported ? "1px solid rgba(111, 207, 151, 0.25)" : "1px solid rgba(235, 87, 87, 0.25)",
                      }}
                    >
                      {webGlSupported ? "3D Dice Active" : "WebGL Offline"}
                    </span>
                    <span style={{ ...styles.themeBadge, ...activeDiceStyle.chip }}>
                      {activeDiceTheme.shortName}
                    </span>
                  </div>
                  <button
                    onClick={handleClear}
                    style={styles.clearBtn}
                    className="touch-target btn-hover-scale glass-panel"
                  >
                    <RotateCcw size={15} />
                    Clear Pool
                  </button>
                </div>

                {/* Dice Selection Grid */}
                <div style={styles.diceGrid} className="dice-roller-grid">
                  {DICE_TYPES.map((die) => {
                    const qty = quantities[die.id] || 0;
                    return (
                      <div
                        key={die.id}
                        style={{
                          ...styles.dieCard,
                          borderColor: qty > 0 ? die.color : "rgba(255,255,255,0.06)",
                          background: qty > 0
                            ? `radial-gradient(circle at 50% 0%, rgba(${diceHexToRgb(activeDiceColor)}, 0.14), transparent 62%), rgba(${diceHexToRgb(die.color)}, 0.08)`
                            : "rgba(255,255,255,0.02)",
                        }}
                        className="glass-panel"
                      >
                        <button
                          onClick={() => handleDieTap(die.id)}
                          style={styles.dieVisualArea}
                          title="Tap to add die"
                          className="touch-target dice-visual-button"
                        >
                          <span
                            style={{
                              ...styles.dieIconFrame,
                              ...(qty > 0 ? activeDiceStyle.die : styles.inactiveDieIconFrame),
                            }}
                          >
                            {die.svg(qty > 0 ? activeDiceTheme.textColor : "var(--color-muted)")}
                          </span>
                          <span style={{ ...styles.dieLabel, color: qty > 0 ? die.color : "var(--color-muted)" }}>
                            {die.label.toUpperCase()}
                          </span>
                        </button>

                        <div style={styles.controlsRow}>
                          <button
                            onClick={() => adjustQuantity(die.id, -1)}
                            style={styles.adjustBtn}
                            className="touch-target"
                            disabled={qty === 0}
                            aria-label={`Remove ${die.label}`}
                          >
                            <Minus size={17} />
                          </button>
                          <span style={{ ...styles.quantityDisplay, color: qty > 0 ? "var(--color-text)" : "var(--color-muted)" }}>
                            {qty}
                          </span>
                          <button
                            onClick={() => adjustQuantity(die.id, 1)}
                            style={styles.adjustBtn}
                            className="touch-target"
                            aria-label={`Add ${die.label}`}
                          >
                            <Plus size={17} />
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              <aside style={styles.buildPanel} className="glass-panel dice-roller-build-panel">
                <div style={styles.buildPanelHeader}>
                  <div>
                    <h3 style={styles.panelTitle}>Roll Setup</h3>
                    <p style={styles.panelMeta}>
                      {selectedDiceCount > 0 ? `${selectedDiceCount} dice selected` : "No dice selected"}
                    </p>
                  </div>
                </div>

                {/* Modifier and Label Section */}
                <div style={styles.setupStack}>
                  <div style={styles.inputGroup}>
                    <label style={styles.inputLabel}>Roll Name / Purpose</label>
                    <input
                      type="text"
                      placeholder="e.g. Stealth check, Fireball damage"
                      value={rollLabel}
                      onChange={(e) => setRollLabel(e.target.value)}
                      style={styles.textInput}
                      className="form-input"
                      maxLength={40}
                    />
                  </div>

                  <div style={styles.inputGroup}>
                    <label style={styles.inputLabel}>Flat Modifier</label>
                    <div style={styles.modifierControl}>
                      <button
                        onClick={() => setModifier((m) => m - 1)}
                        style={styles.modAdjustBtn}
                        className="touch-target"
                        aria-label="Decrease modifier"
                      >
                        <Minus size={17} />
                      </button>
                      <input
                        type="number"
                        value={modifier}
                        onChange={(e) => setModifier(parseInt(e.target.value, 10) || 0)}
                        style={styles.modInput}
                        className="form-input"
                      />
                      <button
                        onClick={() => setModifier((m) => m + 1)}
                        style={styles.modAdjustBtn}
                        className="touch-target"
                        aria-label="Increase modifier"
                      >
                        <Plus size={17} />
                      </button>
                    </div>
                  </div>

                  <div style={styles.inputGroup}>
                    <label style={styles.inputLabel}>d20 Modifiers</label>
                    <div style={styles.advantageGrid} className="dice-advantage-grid">
                      <button
                        onClick={() => handleAdvantageToggle("normal")}
                        style={{
                          ...styles.advBtn,
                          background: advantage === "normal" ? "rgba(255, 255, 255, 0.1)" : "transparent",
                          borderColor: advantage === "normal" ? "var(--color-accent)" : "rgba(255,255,255,0.06)",
                          color: advantage === "normal" ? "var(--color-accent)" : "var(--color-muted)",
                        }}
                        className="touch-target"
                      >
                        Normal
                      </button>
                      <button
                        onClick={() => handleAdvantageToggle("advantage")}
                        style={{
                          ...styles.advBtn,
                          background: advantage === "advantage" ? "rgba(111, 207, 151, 0.15)" : "transparent",
                          borderColor: advantage === "advantage" ? "var(--color-success)" : "rgba(255,255,255,0.06)",
                          color: advantage === "advantage" ? "var(--color-success)" : "var(--color-muted)",
                        }}
                        className="touch-target"
                      >
                        Advantage
                      </button>
                      <button
                        onClick={() => handleAdvantageToggle("disadvantage")}
                        style={{
                          ...styles.advBtn,
                          background: advantage === "disadvantage" ? "rgba(235, 87, 87, 0.15)" : "transparent",
                          borderColor: advantage === "disadvantage" ? "var(--color-danger)" : "rgba(255,255,255,0.06)",
                          color: advantage === "disadvantage" ? "var(--color-danger)" : "var(--color-muted)",
                        }}
                        className="touch-target"
                      >
                        Disadvantage
                      </button>
                    </div>
                  </div>
                </div>

                <div style={styles.desktopRollSummary} className="dice-roll-desktop-summary">
                  {renderRollAction()}
                </div>
              </aside>
            </div>
          ) : (
            /* Roll History List Tab */
            <div style={styles.historyContainer}>
              <h2 style={styles.title}>Shared Roll Log</h2>
              {history.length === 0 ? (
                <div style={styles.emptyHistory} className="glass-panel">
                  No rolls recorded yet in this session.
                </div>
              ) : (
                <div style={styles.historyList}>
                  {history.map((roll) => {
                    let parsedRolls = [];
                    try {
                      parsedRolls = typeof roll.rolls === "string" ? JSON.parse(roll.rolls) : roll.rolls;
                    } catch (e) {
                      parsedRolls = [];
                    }
                    const rollTime = new Date(roll.createdAt).toLocaleTimeString([], {
                      hour: "2-digit",
                      minute: "2-digit",
                      second: "2-digit",
                    });
                    const rollTheme = getDiceThemeOption(roll.diceTheme || "default");
                    const rollThemeStyle = getDiceThemePreviewStyles(rollTheme.id, roll.diceColor || rollTheme.defaultColor);
                    return (
                      <div
                        key={roll.id}
                        style={{
                          ...styles.historyItem,
                          borderLeft: `4px solid ${roll.diceColor || "var(--color-accent)"}`,
                        }}
                        className="glass-panel fade-in"
                      >
                        <div style={styles.historyItemHeader}>
                          <span style={styles.historySender}>{roll.sender}</span>
                          <div style={styles.historyMetaGroup}>
                            <span style={{ ...styles.historyThemeChip, ...rollThemeStyle.chip }}>
                              {rollTheme.shortName}
                            </span>
                            <span style={styles.historyTime}>{rollTime}</span>
                          </div>
                        </div>
                        <div style={styles.historyItemBody}>
                          <div style={styles.historyDetails}>
                            <div style={styles.historyName}>{roll.rollName}</div>
                            <div style={styles.historyFormula}>{roll.formula}</div>
                            <div style={styles.historyBreakdown}>
                              Rolled: ({parsedRolls.join(" + ")}){" "}
                              {roll.modifier !== 0
                                ? roll.modifier > 0
                                  ? `+ ${roll.modifier}`
                                  : `- ${Math.abs(roll.modifier)}`
                                : ""}
                            </div>
                          </div>
                          <div
                            style={{
                              ...styles.historyTotal,
                              color: roll.diceColor || "var(--color-accent)",
                              textShadow: `0 0 10px ${roll.diceColor}44`,
                            }}
                          >
                            {roll.total}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Floating Action / Roll Summary Footer (Only on Roller Tab) */}
      {activeSubTab === "roller" && (
        <div style={styles.footer} className="glass-panel gold-border-glow dice-roll-mobile-footer">
          {renderRollAction()}
        </div>
      )}
    </div>
  );
}

