function formatGold(cp) {
  if (!cp || cp < 0) cp = 0;
  const gold = Math.floor(cp / 100);
  const silver = Math.floor((cp % 100) / 10);
  const copper = cp % 10;
  const parts = [];
  if (gold > 0) parts.push(`${gold} GP`);
  if (silver > 0) parts.push(`${silver} SP`);
  if (copper > 0 || parts.length === 0) parts.push(`${copper} CP`);
  return parts.join(", ");
}

