  useEffect(() => {
    if (!routeArticleId) return;
    const article = articles.find(a => a.id === Number(routeArticleId));
    if (article && article.id !== selectedArticle?.id) {
      setSelectedArticle(article);
    }
  }, [routeArticleId, articles, selectedArticle?.id]);

  // ── Sync selectedArticle → URL for shareable links ─────────────────
  useEffect(() => {
    if (isPopout) return;
    // Derive base path by removing any trailing number segment
    const base = location.pathname.replace(/\/\d+$/, "");
    if (selectedArticle) {
      const expected = `${base}/${selectedArticle.id}`;
      if (location.pathname !== expected) {
        navigate(expected, { replace: true });
      }
    } else if (location.pathname !== base && !routeArticleId) {
        navigate(base, { replace: true });
      }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedArticle?.id, isPopout, location.pathname, navigate, routeArticleId]);

  // ── Real-time wiki sync via Socket.io ──────────────────────────────
  useEffect(() => {
    if (!socket) return;

    const handleCreated = (data) => {
      if (data?.article) {
        setArticles((prev) => [data.article, ...prev]);
      }
    };
    const handleUpdated = (data) => {
      if (data?.article) {
        const updated = data.article;
        setArticles((prev) => prev.map((a) => (a.id === updated.id ? updated : a)));
        setSelectedArticle((prev) => (prev?.id === updated.id ? updated : prev));
      }
    };
    const handleDeleted = (data) => {
      if (data?.id != null) {
        setArticles((prev) => prev.filter((a) => a.id !== data.id));
        setSelectedArticle((prev) => (prev?.id === data.id ? null : prev));
      }
    };

    socket.on("wiki:article:created", handleCreated);
    socket.on("wiki:article:updated", handleUpdated);
    socket.on("wiki:article:deleted", handleDeleted);

    return () => {
      socket.off("wiki:article:created", handleCreated);
      socket.off("wiki:article:updated", handleUpdated);
      socket.off("wiki:article:deleted", handleDeleted);
    };
  }, [socket]);

