                  textAlign: "left",
                }}>
                  <div style={{ fontWeight: "600", color: "var(--color-accent)", marginBottom: "0.25rem", fontSize: "0.72rem" }}>
                    NPC CONCEPT
                  </div>
                  {npcInterviewSummary}
                </div>
              )}
            </div>

            {npcGenError && (
              <p style={{ ...styles.editorErrorText, marginBottom: "1rem", textAlign: "center" }}>⚠️ {npcGenError}</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// =============================================================================
// Tablecast — Wiki Panel Utility Functions (Extracted from WikiPanel)
// Pure utility functions for D&D 5e data formatting and markdown rendering
// =============================================================================
import { marked } from "marked";
import DOMPurify from "dompurify";

/**
 * Calculate ability modifier from a D&D 5e ability score (0-30).
 * @param {number} score - Ability score (defaults to 10)
 * @returns {string} Formatted modifier like "+3" or "-1"
 */
export function calculateModifier(score) {
  const mod = Math.floor((Number(score || 10) - 10) / 2);
  return mod >= 0 ? `+${mod}` : `${mod}`;
}

/**
 * Build an image generation prompt from NPC data for AI art tools.
 * Combines name, race, class, alignment, appearance, personality,
 * description, and equipment into a detailed prompt string.
 * @param {object} npc - NPC or Monster data object
 * @param {string} styleSuffix - Optional DM-configured style suffix
 * @returns {string} Combined prompt string
 */
export function buildImagePrompt(npc, styleSuffix = "") {
  const parts = [];
  // Core identity
  parts.push(`Fantasy portrait of ${npc.name || "an NPC"}`);
  if (npc.race) parts.push(`a ${npc.race}`);
  if (npc.class) parts.push(`${npc.class}`);
  // Alignment / vibe
  if (npc.alignment) parts.push(`with a ${npc.alignment.toLowerCase()} alignment`);
  // Appearance (strip markdown for cleaner prompt)
  if (npc.appearance) {
    const clean = npc.appearance.replace(/[*#>`_~\[\]]/g, "").trim();
    if (clean) parts.push(clean);
  }
  // Personality flavour
  if (npc.personality) {
    const clean = npc.personality.replace(/[*#>`_~\[\]]/g, "").trim().slice(0, 160);
    if (clean) parts.push(`Personality: ${clean}`);
  }
  // Description / location hints
  if (npc.description) {
    const clean = npc.description.replace(/[*#>`_~\[\]]/g, "").trim().slice(0, 200);
    if (clean) parts.push(clean);
  }
  // Gear / equipment from actions
  if (npc.actions) {
    try {
      const actions = JSON.parse(npc.actions);
      const weaponNames = actions.map(a => a.name).filter(Boolean).slice(0, 3);
      if (weaponNames.length > 0) {
        parts.push(`wielding ${weaponNames.join(", ")}`);
      }
    } catch (e) {
      // Silently ignore unparseable actions
    }
  }
  // Default style qualifier
  parts.push("D&D 5e character art, detailed fantasy illustration, full body portrait, professional lighting");
  // Append DM's custom style suffix from settings (if any)
  if (styleSuffix) {
    parts.push(styleSuffix);
  }
  return parts.join(", ");
}

/**
 * Compile Markdown text into safe HTML.
 * Uses `marked` for parsing and DOMPurify for XSS prevention.
 * @param {string} markdownText - Raw markdown text
 * @returns {string} Sanitized HTML string
 */
export function compileMarkdown(markdownText) {
  if (!markdownText) return "";
  try {
    const rawHtml = marked.parse(markdownText);
    return DOMPurify.sanitize(rawHtml);
  } catch (e) {
    console.error("[WikiPanel] Markdown parsing failed:", e);
    return "<p style='color:var(--color-danger);'>Failed to parse content.</p>";
  }
}

/**
 * Parse 5eTools alignment format into a human-readable string.
 * Handles arrays of alignment objects, single-letter codes (L, C, G, E, N, A, U),
 * and raw alignment strings.
 * @param {string|Array} alignment - Raw alignment from 5eTools data
 * @returns {string} Human-readable alignment like "Lawful Good" or "Unaligned"
 */
export function parse5eToolsAlignment(alignment) {
  if (!alignment) return "Unaligned";
  if (typeof alignment === "string") return alignment;
  if (!Array.isArray(alignment)) return "Unaligned";

  const codes = alignment.map(item => {
    if (typeof item === "string") return item;
    if (item && typeof item === "object" && Array.isArray(item.alignment)) {
      return item.alignment;
    }
    return "";
  }).flat().filter(Boolean);

  if (codes.length === 0) return "Unaligned";
  if (codes.includes("A")) return "Any alignment";
  if (codes.includes("U")) return "Unaligned";

  const mapping = {
    L: "Lawful",
    C: "Chaotic",
    G: "Good",
    E: "Evil",
    N: "Neutral"
  };

  if (codes.length === 1 && codes[0] === "N") return "Neutral";

  const words = codes.map(c => mapping[c] || c);
  return words.join(" ");
}

// =============================================================================
// Tablecast — useAiChat Hook
// Shared state management hook for AI chat conversations.
// Provides messages, streaming state, send/cancel/retry/clear actions.
// Used by AiPanel, and can be adopted by ChatPanel for AI interactions.
// =============================================================================

import { useState, useRef, useCallback, useEffect } from "react";
import { streamAiChat } from "../utils/aiStream";
import { getJsonAuthHeaders } from "../utils/authHeaders";

/**
 * @param {Object} opts
 * @param {Object} [opts.user]           - User object with .id
 * @param {string} [opts.initialMessage] - Optional initial assistant message
 * @param {number} [opts.npcId]          - NPC ID for roleplay
 * @param {number} [opts.characterId]    - Character ID for context
 * @param {number} [opts.conversationId] - Existing conversation ID to load
 * @returns {Object} { messages, streaming, error, send, cancel, retry, clearMessages, setMessages }
 */
export function useAiChat({
  user,
  initialMessage = "",
  npcId,
  characterId,
  conversationId: initialConversationId,
} = {}) {
  const [messages, setMessages] = useState(
    initialMessage
      ? [{ role: "assistant", text: initialMessage }]
      : []
  );
  const [streaming, setStreaming] = useState(false);
  const [error, setError] = useState(null);
  const [conversationId, setConversationId] = useState(initialConversationId || null);

  // Ref to store the last sent message for retry
  const lastQueryRef = useRef(null);
  // Ref to the cancel function
  const cancelRef = useRef(null);
  // Ref to track if streaming was intentionally cancelled
  const cancelledRef = useRef(false);
  // Ref to track if component is mounted
  const mountedRef = useRef(true);
  // Ref to the current AbortController
  const controllerRef = useRef(null);
  // Ref to keep messages in sync for multi-turn context (used in send callback)
  const messagesRef = useRef(messages);
  useEffect(() => { messagesRef.current = messages; }, [messages]);

  // Cleanup on unmount — abort in-flight request and prevent state updates
  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
      cancelledRef.current = true;
      if (controllerRef.current) {
        controllerRef.current.abort();
        controllerRef.current = null;
      }
    };
  }, []);

  // Load conversation messages when initialConversationId is provided
  useEffect(() => {
    if (!initialConversationId) return;

    let cancelled = false;

    (async () => {
      try {
        const res = await fetch(`/api/ai/conversations/${initialConversationId}`, {
          headers: getJsonAuthHeaders(user),
        });
        if (!res.ok) return;
        const data = await res.json();
        if (!cancelled && data.messages) {
          setMessages(data.messages.map(m => ({ role: m.role, text: m.text, createdAt: m.createdAt, timestamp: m.createdAt })));
        }
      } catch (err) {
        console.error("[useAiChat] Failed to load conversation:", err);
      }
    })();

    return () => { cancelled = true; };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialConversationId, user?.id]);

  const send = useCallback(
    async (text, overrides = {}) => {
      if (!text?.trim() || streaming) return;

      const query = text.trim();
      lastQueryRef.current = query;
      cancelledRef.current = false;

      // Add user message
      const userMsg = { role: "user", text: query };
      setMessages((prev) => [...prev, userMsg]);

      setStreaming(true);
      setError(null);

      let assistantStarted = false;
      let accumulated = "";

      const controller = new AbortController();
      controllerRef.current = controller;
      cancelRef.current = () => controller.abort();

      try {
        // Build multi-turn context from current messages (excluding the system message)
        const history = messagesRef.current
          .filter((m) => m.role !== "system")
          .map((m) => ({ role: m.role, text: m.text }));

        const result = await streamAiChat({
          user,
          message: query,
          history,
          npcId: overrides.npcId ?? npcId,
          characterId: overrides.characterId ?? characterId,
          conversationId: overrides.conversationId ?? conversationId,
          stream: true,
          signal: controller.signal,
          onToken: (token) => {
            if (!mountedRef.current || cancelledRef.current) return;
            accumulated += token;
            setMessages((prev) => {
              if (!assistantStarted) {
                assistantStarted = true;
                return [...prev, { role: "assistant", text: accumulated }];
              }
              const copy = [...prev];
              copy[copy.length - 1] = { role: "assistant", text: accumulated };
              return copy;
            });
          },
        });

        if (!mountedRef.current) return;

        // If server returned a conversationId from auto-save, track it
        if (result?.conversationId) {
          setConversationId(result.conversationId);
        }

        // Attach rollChips to the last assistant message if present
        if (result?.rollChips && result.rollChips.length > 0) {
          setMessages((prev) => {
            const copy = [...prev];
            const last = copy[copy.length - 1];
            if (last && last.role === "assistant") {
              copy[copy.length - 1] = { ...last, rollChips: result.rollChips };
            }
            return copy;
          });
        }
      } catch (err) {
        if (err.name === "AbortError" || !mountedRef.current || cancelledRef.current) return;

        const errorText = err.message || "Connection lost.";
        if (!mountedRef.current) return;
        setError(errorText);

        if (mountedRef.current) {
          setMessages((prev) => {
            if (!assistantStarted) {
              return [...prev, { role: "assistant", text: `Error: ${errorText}` }];
            }
            const copy = [...prev];
            const last = copy[copy.length - 1];
            copy[copy.length - 1] = {
              role: "assistant",
              text: accumulated
                ? `${accumulated}\n\n*Error: ${errorText}*`
                : `Error: ${errorText}`,
            };
            return copy;
          });
        }
      } finally {
        if (mountedRef.current) {
          setStreaming(false);
        }
        cancelRef.current = null;
        controllerRef.current = null;
      }
    },
    [user, streaming, npcId, characterId, conversationId]
  );

  const cancel = useCallback(() => {
    cancelledRef.current = true;
    if (cancelRef.current) {
      cancelRef.current();
      cancelRef.current = null;
    }
    setStreaming(false);
  }, []);

  const retry = useCallback(async () => {
    if (!lastQueryRef.current) return;
    // Remove the last user + assistant messages (if any)
    setMessages((prev) => {
      // Remove last assistant message if it was an error
      const copy = [...prev];
      if (copy.length >= 2 && copy[copy.length - 1].role === "assistant") {
        copy.pop(); // remove assistant error/partial
      }
      if (copy.length >= 1 && copy[copy.length - 1].role === "user") {
        copy.pop(); // remove the user message that triggered the error
      }
      return copy;
    });
    await send(lastQueryRef.current);
  }, [send]);

  const clearMessages = useCallback(
    (newInitialMessage = "") => {
      setMessages(
        newInitialMessage
          ? [{ role: "assistant", text: newInitialMessage }]
          : []
      );
      setError(null);
      lastQueryRef.current = null;
    },
    []
  );

  const loadConversation = useCallback((conv) => {
    setConversationId(conv.id);
    setMessages(
      conv.messages?.map((m) => ({ role: m.role, text: m.text })) || []
    );
    setError(null);
  }, []);

  return {
    messages,
    setMessages,
    streaming,
    error,
    conversationId,
    setConversationId,
    send,
    cancel,
    retry,
    clearMessages,
    loadConversation,
    lastQueryRef,
  };
}

// =============================================================================
// Tablecast — AI Chat & Conversation Routes
// Chat with AI assistant, NPC roleplay, conversation management
// =============================================================================
"use strict";

const { Router } = require("express");
const prisma = require("../prisma");
const logger = require("../utils/logger");
const { getRequestUser } = require("../auth");
const {
  loadAiSettings, performAiCall, performAiStreamTokens, performAiStream,
  findRelevantRules, buildNpcRoleplaySystemPrompt,
  beginSseResponse, writeSseEvent
} = require("./helpers");
const { scanTextForRollChips } = require("../utils/diceRollDetection");

const router = Router();

// ---------------------------------------------------------------------------
// POST /chat - Process built-in D&D assistant chat
// ---------------------------------------------------------------------------
router.post("/chat", async (req, res) => {
  try {
    const { message, npcId, history, stream: wantsStream, conversationId, characterId } = req.body;
    if (!message || typeof message !== "string" || !message.trim()) {
      return res.status(400).json({ error: "Message content is required." });
    }
    if (message.length > 10000) {
      return res.status(400).json({ error: "Message too long. Maximum 10,000 characters." });
    }

    const user = await getRequestUser(req);
    if (!user) {
      return res.status(401).json({ error: "Authentication required to use AI Chat." });
    }

    const { provider, apiKey, ollamaUrl, ollamaModel, model } = await loadAiSettings();

    if (!provider) {
      return res.status(400).json({ error: "AI assistant is not configured. Please ask the DM to set up API keys in Settings." });
    }

    // 1. Fetch relevant local reference material (enforces visibility constraints)
    const referenceContext = await findRelevantRules(message, user);

    // 2. Build system instructions
    let systemPrompt = `You are a helpful D&D 5e assistant, dungeon master helper, and rules scholar.
You have access to a local D&D database. Whenever relevant, rely on the rules matches provided in the prompt context to answer questions accurately and authoritatively.

${referenceContext}

Keep your responses concise, readable, and structured in Markdown.`;

    if (npcId) {
      const npc = await prisma.npc.findUnique({ where: { id: Number(npcId) } });
      if (npc) {
        if (user.role !== "DM" && !npc.isVisibleToPlayers) {
          return res.status(403).json({ error: "This NPC is not available for roleplay." });
        }
        systemPrompt = buildNpcRoleplaySystemPrompt(npc, referenceContext);
      }
    }

    // Inject character context if characterId provided
    if (characterId) {
      try {
        const character = await prisma.character.findUnique({
          where: { id: Number(characterId) },
          select: { userId: true, name: true, race: true, class: true, level: true, hp: true, maxHp: true, strength: true, dexterity: true, constitution: true, intelligence: true, wisdom: true, charisma: true },
        });
        if (character) {
          if (user.role !== "DM" && character.userId !== user.id) {
            return res.status(403).json({ error: "You are not authorized to use this character." });
          }
          const charContext = `\n=== PLAYER CHARACTER CONTEXT ===\nName: ${character.name}\nRace: ${character.race || "unknown"}\nClass: ${character.class || "unknown"}\nLevel: ${character.level}\nHP: ${character.hp}/${character.maxHp}\nStats: STR ${character.strength} DEX ${character.dexterity} CON ${character.constitution} INT ${character.intelligence} WIS ${character.wisdom} CHA ${character.charisma}\n================================\n`;
          if (npcId) {
            systemPrompt += `\nThe player's character speaking to you is:\n${charContext}`;
          } else {
            systemPrompt += `\nThe player's character (for context):\n${charContext}`;
          }
        }
      } catch (charErr) {
        logger.error("ai:chat", "Failed to fetch character context", { error: charErr.message });
      }
    }

    const activeModel = provider === "opencode" ? (model || "gpt-5-nano") : ollamaModel;

    if (wantsStream) {
      beginSseResponse(res);
      const controller = new AbortController();
      req.on("close", () => controller.abort());

      writeSseEvent(res, { type: "context", text: referenceContext });

      let fullResponse = "";

      try {
        await performAiStreamTokens(
          provider,
          apiKey,
          ollamaUrl,
          activeModel,
          systemPrompt,
          message,
          history,
          (token) => {
            fullResponse += token;
            writeSseEvent(res, { type: "token", text: token });
          },
          controller.signal
        );

        if (conversationId) {
          try {
            const convId = Number(conversationId);
            const conv = await prisma.aiConversation.findUnique({
              where: { id: convId },
              select: { userId: true },
            });
            if (conv && conv.userId === user.id) {
              await prisma.aiMessage.createMany({
                data: [
                  { conversationId: convId, role: "user", text: message },
                  { conversationId: convId, role: "assistant", text: fullResponse },
                ],
              });
              await prisma.aiConversation.update({
                where: { id: convId },
                data: { updatedAt: new Date() },
              });
            }
          } catch (saveErr) {
            logger.error("ai:chat", "Failed to auto-save conversation", { error: saveErr.message });
          }
        }

        // Scan for dice roll chips in the completed response
        const rollChips = scanTextForRollChips(fullResponse);
        if (rollChips.length > 0) {
          writeSseEvent(res, { type: "rollChips", chips: rollChips });
        }

        writeSseEvent(res, { type: "done" });
      } catch (streamErr) {
        if (streamErr.name === "AbortError") {
          return;
        }
        logger.error("ai:chat", "Streaming failed", { error: streamErr.message });
        writeSseEvent(res, { type: "error", message: streamErr.message || "Failed to query AI assistant." });
      }

      res.end();
      return;
    }

    // Non-streaming response
    const reply = await performAiCall(provider, apiKey, ollamaUrl, activeModel, systemPrompt, message, history, "chat");

    if (conversationId) {
      try {
        const convId = Number(conversationId);
        const conv = await prisma.aiConversation.findUnique({
          where: { id: convId },
          select: { userId: true },
        });
        if (conv && conv.userId === user.id) {
          await prisma.aiMessage.createMany({
            data: [
              { conversationId: convId, role: "user", text: message },
              { conversationId: convId, role: "assistant", text: reply },
            ],
          });
          await prisma.aiConversation.update({
            where: { id: convId },
            data: { updatedAt: new Date() },
          });
        }
      } catch (saveErr) {
        logger.error("ai:chat", "Failed to auto-save conversation", { error: saveErr.message });
      }
    }

    const rollChips = scanTextForRollChips(reply);

    res.json({ reply, context: referenceContext, conversationId: conversationId || null, rollChips: rollChips.length > 0 ? rollChips : undefined });
  } catch (err) {
    logger.error("ai:chat", "Chat operation failed", { error: err.message });
    if (res.headersSent) {
      writeSseEvent(res, { type: "error", message: err.message || "Failed to query AI assistant." });
      res.end();
      return;
    }
    res.status(500).json({ error: err.message || "Failed to query AI assistant." });
  }
});

// ---------------------------------------------------------------------------
// AI Conversation Management
// ---------------------------------------------------------------------------

// GET /conversations — List user's conversations
router.get("/conversations", async (req, res) => {
  try {
    const user = await getRequestUser(req);
    if (!user) return res.status(401).json({ error: "Authentication required." });

    const conversations = await prisma.aiConversation.findMany({
      where: { userId: user.id },
      orderBy: { updatedAt: "desc" },
      include: { _count: { select: { messages: true } } },
    });
    res.json(conversations);
  } catch (err) {
    logger.error("ai:conversations", "List failed", { error: err.message });
    res.status(500).json({ error: err.message });
  }
});

// POST /conversations — Create new conversation
router.post("/conversations", async (req, res) => {
  try {
    const user = await getRequestUser(req);
    if (!user) return res.status(401).json({ error: "Authentication required." });

    const { type, npcId, title } = req.body;
    const conversation = await prisma.aiConversation.create({
      data: {
        userId: user.id,
        type: type || "rules",
        npcId: npcId || null,
        title: title || "",
      },
    });
    res.status(201).json(conversation);
  } catch (err) {
    logger.error("ai:conversations", "Create failed", { error: err.message });
    res.status(500).json({ error: err.message });
  }
});

// GET /conversations/:id — Get conversation with messages
router.get("/conversations/:id", async (req, res) => {
  try {
    const user = await getRequestUser(req);
    if (!user) return res.status(401).json({ error: "Authentication required." });

    const conversation = await prisma.aiConversation.findFirst({
      where: { id: Number(req.params.id), userId: user.id },
      include: { messages: { orderBy: { createdAt: "asc" } } },
    });
    if (!conversation) return res.status(404).json({ error: "Conversation not found." });
    res.json(conversation);
  } catch (err) {
    logger.error("ai:conversations", "Get failed", { error: err.message });
    res.status(500).json({ error: err.message });
  }
});

// PATCH /conversations/:id — Update conversation title
router.patch("/conversations/:id", async (req, res) => {
  try {
    const user = await getRequestUser(req);
    if (!user) return res.status(401).json({ error: "Authentication required." });

    const { title } = req.body;
    const conversation = await prisma.aiConversation.findFirst({
      where: { id: Number(req.params.id), userId: user.id },
    });
    if (!conversation) return res.status(404).json({ error: "Conversation not found." });

    const updated = await prisma.aiConversation.update({
      where: { id: Number(req.params.id) },
      data: { title: title || "" },
    });
    res.json(updated);
  } catch (err) {
    logger.error("ai:conversations", "Update failed", { error: err.message });
    res.status(500).json({ error: err.message });
  }
});

// DELETE /conversations/:id — Delete conversation
router.delete("/conversations/:id", async (req, res) => {
  try {
    const user = await getRequestUser(req);
    if (!user) return res.status(401).json({ error: "Authentication required." });

    const conversation = await prisma.aiConversation.findFirst({
      where: { id: Number(req.params.id), userId: user.id },
    });
    if (!conversation) return res.status(404).json({ error: "Conversation not found." });

    await prisma.aiConversation.delete({ where: { id: Number(req.params.id) } });
    res.json({ success: true });
  } catch (err) {
    logger.error("ai:conversations", "Delete failed", { error: err.message });
    res.status(500).json({ error: err.message });
  }
});

// POST /conversations/:id/messages — Batch-save messages to a conversation
router.post("/conversations/:id/messages", async (req, res) => {
  try {
    const user = await getRequestUser(req);
    if (!user) return res.status(401).json({ error: "Authentication required." });

    const { messages } = req.body;
    if (!messages || !Array.isArray(messages) || messages.length === 0) {
      return res.status(400).json({ error: "Messages array is required." });
    }
    if (messages.length > 50) {
      return res.status(400).json({ error: "Maximum 50 messages per batch." });
    }

    const conversation = await prisma.aiConversation.findFirst({
      where: { id: Number(req.params.id), userId: user.id },
    });
    if (!conversation) return res.status(404).json({ error: "Conversation not found." });

    const VALID_ROLES = new Set(["user", "assistant"]);
    const created = await prisma.$transaction(
      messages.map((msg) => {
        const role = VALID_ROLES.has(msg.role) ? msg.role : "user";
        const text = (msg.text || "").slice(0, 10000);
        return prisma.aiMessage.create({
          data: {
            conversationId: Number(req.params.id),
            role,
            text,
          },
        });
      })
    );

    // Auto-generate title from first exchange if empty
    if (!conversation.title && messages.length > 0) {
      const firstUserMsg = messages.find(m => m.role === "user");
      const generatedTitle = firstUserMsg
        ? firstUserMsg.text.slice(0, 80) + (firstUserMsg.text.length > 80 ? "…" : "")
        : "";
      if (generatedTitle) {
        await prisma.aiConversation.update({
          where: { id: Number(req.params.id) },
          data: { title: generatedTitle },
