"use strict";

async function handleListCharacters(args, { prisma }) {
  const filter = {};
  if (typeof args.userId === "number") {
    filter.userId = args.userId;
  }
  const characters = await prisma.character.findMany({
    where: filter,
    orderBy: { id: "asc" },
  });

  // Parse JSON fields back to standard JSON types for tool response formatting
  const parsed = characters.map((c) => ({
    ...c,
    inventory: JSON.parse(c.inventory || "[]"),
    modifiers: JSON.parse(c.modifiers || "{}"),
  }));

  return {
    content: [{ type: "text", text: JSON.stringify(parsed, null, 2) }],
  };
}

async function handleCreateCharacter(args, { prisma, generateModifiers }) {
  const { userId, name: charName, race, class: cls, level, hp, maxHp, ...rest } = args;

  // userId is optional - if provided, verify the user exists
  if (userId) {
    const owner = await prisma.user.findUnique({ where: { id: userId } });
    if (!owner) {
      throw new Error(`User with ID ${userId} does not exist.`);
    }
  }

  // Extract base stats
  const strength = rest.strength ?? 10;
  const dexterity = rest.dexterity ?? 10;
  const constitution = rest.constitution ?? 10;
  const intelligence = rest.intelligence ?? 10;
  const wisdom = rest.wisdom ?? 10;
  const charisma = rest.charisma ?? 10;

  // Modifiers auto-calculation or manual override
  const computedMods = rest.modifiers || generateModifiers({
    strength,
    dexterity,
    constitution,
    intelligence,
    wisdom,
    charisma,
  });

  const inventoryStr = JSON.stringify(args.inventory || []);
  const modifiersStr = JSON.stringify(computedMods);

  const characterData = {
    name: charName,
    race: race || "",
    class: cls || "",
    level: level || 1,
    hp: hp ?? 10,
    maxHp: maxHp ?? 10,
    strength,
    dexterity,
    constitution,
    intelligence,
    wisdom,
    charisma,
    inventory: inventoryStr,
    modifiers: modifiersStr,
  };
  if (userId) characterData.userId = userId;

  const character = await prisma.character.create({
    data: characterData,
  });

  const parsed = {
    ...character,
    inventory: JSON.parse(character.inventory),
    modifiers: JSON.parse(character.modifiers),
  };

  return {
    content: [
      { type: "text", text: `Character created successfully:\n${JSON.stringify(parsed, null, 2)}` },
    ],
  };
}

async function handleUpdateCharacter(args, { prisma, generateModifiers }) {
  const { id, name: charName, race, class: cls, level, hp, maxHp, inventory, modifiers, ...statsUpdate } = args;

  // Load existing character to handle stat merging and modifier calculation
  const existing = await prisma.character.findUnique({ where: { id } });
  if (!existing) {
    throw new Error(`Character with ID ${id} not found.`);
  }

  const dataUpdate = {};

  if (charName !== undefined) dataUpdate.name = charName;
  if (race !== undefined) dataUpdate.race = race;
  if (cls !== undefined) dataUpdate.class = cls;
  if (level !== undefined) dataUpdate.level = level;
  if (hp !== undefined) dataUpdate.hp = hp;
  if (maxHp !== undefined) dataUpdate.maxHp = maxHp;

  // Merge stats if updated
  let statsChanged = false;
  const statKeys = ["strength", "dexterity", "constitution", "intelligence", "wisdom", "charisma"];
  for (const key of statKeys) {
    if (statsUpdate[key] !== undefined) {
      dataUpdate[key] = statsUpdate[key];
      statsChanged = true;
    }
  }

  if (inventory !== undefined) {
    dataUpdate.inventory = JSON.stringify(inventory);
  }

  if (modifiers !== undefined) {
    dataUpdate.modifiers = JSON.stringify(modifiers);
  } else if (statsChanged) {
    // If stats changed and no custom modifiers override was passed, recalculate modifiers
    const strength = statsUpdate.strength ?? existing.strength;
    const dexterity = statsUpdate.dexterity ?? existing.dexterity;
    const constitution = statsUpdate.constitution ?? existing.constitution;
    const intelligence = statsUpdate.intelligence ?? existing.intelligence;
    const wisdom = statsUpdate.wisdom ?? existing.wisdom;
    const charisma = statsUpdate.charisma ?? existing.charisma;

    const recomputed = generateModifiers({
      strength,
      dexterity,
      constitution,
      intelligence,
      wisdom,
      charisma,
    });
    dataUpdate.modifiers = JSON.stringify(recomputed);
  }

  const updated = await prisma.character.update({
    where: { id },
    data: dataUpdate,
  });

  const parsed = {
    ...updated,
    inventory: JSON.parse(updated.inventory),
    modifiers: JSON.parse(updated.modifiers),
  };

  return {
    content: [
      { type: "text", text: `Character updated successfully:\n${JSON.stringify(parsed, null, 2)}` },
    ],
  };
}

async function handleDeleteCharacter(args, { prisma }) {
  const { id } = args;
  await prisma.character.delete({ where: { id } });
  return {
    content: [{ type: "text", text: `Character with ID ${id} deleted successfully.` }],
  };
}

async function handleAddItemToCharacter(args, { prisma }) {
  const { characterId, name: itemName, quantity, weight } = args;

  const character = await prisma.character.findUnique({ where: { id: characterId } });
  if (!character) {
    throw new Error(`Character with ID ${characterId} not found.`);
  }

  let inv = [];
  try {
    inv = JSON.parse(character.inventory || "[]");
  } catch (e) {
    inv = [];
  }

  const existingItem = inv.find((i) => i && i.name && i.name.toLowerCase() === itemName.toLowerCase());
  const qtyToAdd = quantity ?? 1;

  if (existingItem) {
    existingItem.quantity = (existingItem.quantity || 1) + qtyToAdd;
  } else {
    inv.push({
      name: itemName,
      quantity: qtyToAdd,
      weight: weight ?? 0,
    });
  }

  const updated = await prisma.character.update({
    where: { id: characterId },
    data: { inventory: JSON.stringify(inv) },
  });

  return {
    content: [{ type: "text", text: `Item '${itemName}' successfully added to character '${character.name}'. New inventory:\n${JSON.stringify(inv, null, 2)}` }],
  };
}

module.exports = {
  handleListCharacters,
  handleCreateCharacter,
  handleUpdateCharacter,
  handleDeleteCharacter,
  handleAddItemToCharacter,
};

// =============================================================================
// Tablecast MCP — Dialogue Tree Tool Handlers
// =============================================================================
"use strict";

const {
  resolveNode,
  getStartNode,
  evaluateCondition,
  executeAction,
  pickWeightedRandom,
} = require("../../utils/dialogueEngine");

async function handleGetNpcDialogue(args, { prisma, logError }) {
  const npcId = Number(args.npcId);
  if (!Number.isInteger(npcId) || npcId < 1) {
    throw new Error("npcId must be a positive integer.");
  }

  const npc = await prisma.npc.findUnique({ where: { id: npcId } });
  if (!npc) {
    throw new Error(`NPC with ID ${npcId} not found.`);
  }

  let dialogueTree = { startNodeId: null, nodes: [] };
  try {
    dialogueTree = JSON.parse(npc.dialogueTree || "{}");
  } catch {
    dialogueTree = { startNodeId: null, nodes: [] };
  }

  return {
    content: [{ type: "text", text: JSON.stringify({ npcId, npcName: npc.name, dialogueTree }, null, 2) }],
  };
}

async function handleUpdateNpcDialogue(args, { prisma, logError }) {
  const npcId = Number(args.npcId);
  if (!Number.isInteger(npcId) || npcId < 1) {
    throw new Error("npcId must be a positive integer.");
  }

  const npc = await prisma.npc.findUnique({ where: { id: npcId } });
  if (!npc) {
    throw new Error(`NPC with ID ${npcId} not found.`);
  }

  const { dialogueTree } = args;
  if (!dialogueTree || typeof dialogueTree !== "object") {
    throw new Error("dialogueTree must be a valid JSON object.");
  }

  if (!dialogueTree.startNodeId || !Array.isArray(dialogueTree.nodes)) {
    throw new Error("dialogueTree must have a startNodeId and a nodes array.");
  }

  const updated = await prisma.npc.update({
    where: { id: npcId },
    data: { dialogueTree: JSON.stringify(dialogueTree) },
  });

  return {
    content: [{
      type: "text",
      text: `Dialogue tree updated for NPC '${updated.name}' (ID: ${npcId}). Node count: ${dialogueTree.nodes.length}.`,
    }],
  };
}

async function handleStartNpcDialogue(args, { prisma, getIo, logError }) {
  const npcId = Number(args.npcId);
  if (!Number.isInteger(npcId) || npcId < 1) {
    throw new Error("npcId must be a positive integer.");
  }

  const npc = await prisma.npc.findUnique({ where: { id: npcId } });
  if (!npc) {
    throw new Error(`NPC with ID ${npcId} not found.`);
  }

  let dialogueTree = { startNodeId: null, nodes: [] };
  try {
    dialogueTree = JSON.parse(npc.dialogueTree || "{}");
  } catch {
    dialogueTree = { startNodeId: null, nodes: [] };
  }

  const startNode = getStartNode(dialogueTree);
  if (!startNode) {
    throw new Error("Dialogue tree has no valid start node.");
  }

  // Broadcast dialogue:start via Socket.io
  try {
    const io = getIo();
    if (io) {
      io.emit("dialogue:start", { npcId, npcName: npc.name, startNode });
    }
  } catch (err) {
    logError("Failed to broadcast dialogue:start:", err.message);
  }

  return {
    content: [{
      type: "text",
      text: JSON.stringify({ npcId, npcName: npc.name, node: startNode }, null, 2),
    }],
  };
}

async function handleAdvanceNpcDialogue(args, { prisma, getIo, logError }) {
  const npcId = Number(args.npcId);
  if (!Number.isInteger(npcId) || npcId < 1) {
    throw new Error("npcId must be a positive integer.");
  }

  const npc = await prisma.npc.findUnique({ where: { id: npcId } });
  if (!npc) {
    throw new Error(`NPC with ID ${npcId} not found.`);
  }

  const { nodeId, choiceIndex, rollResult, context } = args;
  if (!nodeId || typeof nodeId !== "string") {
    throw new Error("nodeId (string) is required.");
  }

  let dialogueTree = { startNodeId: null, nodes: [] };
  try {
    dialogueTree = JSON.parse(npc.dialogueTree || "{}");
  } catch {
    dialogueTree = { startNodeId: null, nodes: [] };
  }

  const node = resolveNode(dialogueTree, nodeId);
  if (!node) {
    throw new Error(`Node '${nodeId}' not found in dialogue tree.`);
  }

  let nextNode = null;
  const messages = [];

  switch (node.type) {
    case "SPEECH":
    case "ACTION": {
      if (node.type === "ACTION") {
        const result = executeAction(node.actionType, node.actionPayload, context);
        messages.push(result.message);
      }
      if (node.nextNodeId) {
        nextNode = resolveNode(dialogueTree, node.nextNodeId);
      }
      break;
    }

    case "CHOICE": {
      if (choiceIndex === undefined || choiceIndex === null) {
        throw new Error("choiceIndex is required for CHOICE nodes.");
      }
      const choices = node.choices || [];
      const selected = choices[choiceIndex];
      if (!selected) {
        throw new Error(`Invalid choiceIndex ${choiceIndex}.`);
      }
      if (selected.nextNodeId) {
        nextNode = resolveNode(dialogueTree, selected.nextNodeId);
      }
      messages.push(`Selected: "${selected.text}"`);
      break;
    }

    case "CONDITION": {
      const conditionCtx = { ...(context || {}), roll: rollResult || 0 };
      const conditionMet = evaluateCondition(node.condition, conditionCtx);
      const targetNodeId = conditionMet ? node.trueNextNodeId : node.falseNextNodeId;
      messages.push(conditionMet ? "Condition met." : "Condition not met.");
      if (targetNodeId) {
        nextNode = resolveNode(dialogueTree, targetNodeId);
      }
      break;
    }

    case "SKILL_CHECK": {
      const skillRoll = rollResult !== undefined ? rollResult : 10;
      const passed = skillRoll >= (node.dc || 10);
      const targetNodeId = passed ? node.successNodeId : node.failureNodeId;
      messages.push(
        `${node.skill || "Skill"} check: rolled ${skillRoll} vs DC ${node.dc || 10} — ${passed ? "Success!" : "Failure."}`
      );
      if (targetNodeId) {
        nextNode = resolveNode(dialogueTree, targetNodeId);
      }
      break;
    }

    case "RANDOM": {
      const selectedChoice = pickWeightedRandom(node.choices);
      if (selectedChoice && selectedChoice.nextNodeId) {
        nextNode = resolveNode(dialogueTree, selectedChoice.nextNodeId);
      }
      messages.push("Random choice resolved.");
      break;
    }

    default:
      throw new Error(`Unknown node type: ${node.type}`);
  }

  // Broadcast dialogue:advance via Socket.io
  try {
    const io = getIo();
    if (io && nextNode) {
      io.emit("dialogue:advance", { npcId, node: nextNode, messages });
    }
  } catch (err) {
    logError("Failed to broadcast dialogue:advance:", err.message);
  }

  return {
    content: [{
      type: "text",
      text: JSON.stringify({ npcId, npcName: npc.name, previousNode: node, nextNode, messages }, null, 2),
    }],
  };
}

module.exports = {
  handleGetNpcDialogue,
  handleUpdateNpcDialogue,
  handleStartNpcDialogue,
  handleAdvanceNpcDialogue,
};

// =============================================================================
// Tablecast MCP — Encounter Template Tool Handlers
// =============================================================================
"use strict";

const VALID_DIFFICULTIES = new Set(["easy", "medium", "hard", "deadly"]);

async function handleListEncounterTemplates(args, { prisma, parseJsonArray }) {
  const filter = {};
  if (args.difficulty !== undefined) {
    const difficulty = String(args.difficulty).toLowerCase();
    if (!VALID_DIFFICULTIES.has(difficulty)) {
      throw new Error("Encounter template difficulty must be easy, medium, hard, or deadly.");
    }
    filter.difficulty = difficulty;
  }

  const templates = await prisma.encounterTemplate.findMany({
    where: filter,
    orderBy: { updatedAt: "desc" },
  });

  const parsed = templates.map((t) => ({
    ...t,
    tags: parseJsonArray(t.tags),
    participants: parseJsonArray(t.participants),
  }));

  return {
    content: [{ type: "text", text: JSON.stringify(parsed, null, 2) }],
  };
}

async function handleCreateEncounterTemplate(args, { prisma, toJsonArrayString }) {
  const { name, description, difficulty, recommendedLevel, tags, participants, mapId } = args;

  if (!name || typeof name !== "string" || !name.trim()) {
    throw new Error("Encounter template name is required.");
  }

  const nextDifficulty = difficulty ? String(difficulty).toLowerCase() : "medium";
  if (!VALID_DIFFICULTIES.has(nextDifficulty)) {
    throw new Error("Encounter template difficulty must be easy, medium, hard, or deadly.");
  }

  const data = {
    name: name.trim(),
    description: description || "",
    difficulty: nextDifficulty,
    recommendedLevel: recommendedLevel !== undefined ? Number(recommendedLevel) : 1,
    tags: tags !== undefined ? JSON.stringify(tags) : "[]",
    participants: participants !== undefined ? JSON.stringify(participants) : "[]",
  };

  if (mapId !== undefined && mapId !== null) {
    data.mapId = Number(mapId);
  }

  const template = await prisma.encounterTemplate.create({ data });

  const parsed = {
    ...template,
    tags: JSON.parse(template.tags || "[]"),
    participants: JSON.parse(template.participants || "[]"),
  };

  return {
    content: [{ type: "text", text: `Encounter template created successfully:\n${JSON.stringify(parsed, null, 2)}` }],
  };
}

async function handleUpdateEncounterTemplate(args, { prisma }) {
  const { id, name, description, difficulty, recommendedLevel, tags, participants, mapId } = args;

  const templateId = Number(id);
  if (!Number.isInteger(templateId) || templateId <= 0) {
    throw new Error("Encounter template id must be a valid positive number.");
  }

  const existing = await prisma.encounterTemplate.findUnique({ where: { id: templateId } });
  if (!existing) {
    throw new Error(`Encounter template with ID ${templateId} not found.`);
  }

  const data = {};

  if (name !== undefined) {
    if (!String(name || "").trim()) {
      throw new Error("name must be a non-empty string.");
    }
    data.name = String(name).trim();
  }

  if (description !== undefined) {
    data.description = String(description);
  }

  if (difficulty !== undefined) {
    const nextDifficulty = String(difficulty).toLowerCase();
    if (!VALID_DIFFICULTIES.has(nextDifficulty)) {
      throw new Error("Encounter template difficulty must be easy, medium, hard, or deadly.");
    }
    data.difficulty = nextDifficulty;
  }

  if (recommendedLevel !== undefined) {
    data.recommendedLevel = Number(recommendedLevel);
  }

  if (tags !== undefined) {
    data.tags = JSON.stringify(tags);
  }

  if (participants !== undefined) {
    data.participants = JSON.stringify(participants);
  }

  if (mapId !== undefined) {
    data.mapId = mapId === null ? null : Number(mapId);
  }

  if (Object.keys(data).length === 0) {
    throw new Error("No valid encounter template fields provided to update.");
  }

  const template = await prisma.encounterTemplate.update({
    where: { id: templateId },
    data,
  });

  const parsed = {
    ...template,
    tags: JSON.parse(template.tags || "[]"),
    participants: JSON.parse(template.participants || "[]"),
  };

  return {
    content: [{ type: "text", text: `Encounter template updated successfully:\n${JSON.stringify(parsed, null, 2)}` }],
  };
}

async function handleDeleteEncounterTemplate(args, { prisma }) {
  const { id } = args;

  const templateId = Number(id);
  if (!Number.isInteger(templateId) || templateId <= 0) {
    throw new Error("Encounter template id must be a valid positive number.");
  }

  await prisma.encounterTemplate.delete({ where: { id: templateId } });

  return {
    content: [{ type: "text", text: `Encounter template with ID ${templateId} deleted successfully.` }],
  };
}

async function handleApplyEncounterTemplate(args, { prisma, parseJsonArray }) {
  const { templateId, mapId: overrideMapId, name: encounterName } = args;

  // Validate templateId
  const tId = Number(templateId);
  if (!Number.isInteger(tId) || tId <= 0) {
    throw new Error("Encounter template id must be a valid positive number.");
  }

  // Fetch template
  const template = await prisma.encounterTemplate.findUnique({ where: { id: tId } });
  if (!template) {
    throw new Error("Encounter template not found.");
  }

  // Determine mapId: args ?? template ?? undefined
  const mapId = overrideMapId !== undefined ? Number(overrideMapId) : (template.mapId ?? undefined);

  // Create encounter
  const encounter = await prisma.encounter.create({
    data: {
      name: encounterName || template.name,
      status: "DRAFT",
      ...(mapId !== undefined ? { mapId } : {}),
    },
  });

  // Parse participants and create participant records
  const participants = parseJsonArray(template.participants);

  for (const entry of participants) {
    const count = Math.max(1, Math.round(Number(entry.count || 1)));
    const baseName = String(entry.name || "Combatant").trim();

    for (let i = 0; i < count; i++) {
      const label = count > 1 ? `${baseName} ${i + 1}` : baseName;
      await prisma.encounterParticipant.create({
        data: {
          encounterId: encounter.id,
          name: label,
          currentHp: 1,
          maxHp: 1,
          ac: 10,
          initiative: 0,
        },
      });
    }
  }

  // Fetch the encounter with participants included
  const result = await prisma.encounter.findUnique({
    where: { id: encounter.id },
    include: { participants: true },
  });

  return {
    content: [{ type: "text", text: `Encounter created from template successfully:\n${JSON.stringify(result, null, 2)}` }],
  };
}

module.exports = {
  handleListEncounterTemplates,
  handleCreateEncounterTemplate,
  handleUpdateEncounterTemplate,
  handleDeleteEncounterTemplate,
  handleApplyEncounterTemplate,
};

