});

router.post("/:id/start", requireDm, async (req, res) => {
  try {
    const encounter = await fetchEncounter(req.params.id);
    if (!encounter) return res.status(404).json({ error: "Encounter not found." });
    if (encounter.participants.length === 0) {
      return res.status(400).json({ error: "Add participants before starting combat." });
    }

    const rollInitiative = req.body?.rollInitiative !== false;
    for (const participant of encounter.participants) {
      if (!rollInitiative) continue;
      const dex = participant.character?.dexterity || participant.npc?.dexterity || parseJson(participant.stats, {})?.dex || 10;
      await prisma.encounterParticipant.update({
        where: { id: participant.id },
        data: { initiative: rollD20(getModifier(dex)) },
      });
    }

    await prisma.encounter.update({
      where: { id: encounter.id },
      data: { status: "ACTIVE", round: 1, turnIndex: 0 },
    });
    await respondEncounter(req, res, encounter.id);
  } catch (err) {
    logger.error("api:route", "Error in POST /api/encounters/:id/start", { error: err.message });
    res.status(500).json({ error: "Failed to start encounter." });
  }
});

router.post("/:id/turn", requireDm, async (req, res) => {
  try {
    const encounter = await fetchEncounter(req.params.id);
    if (!encounter) return res.status(404).json({ error: "Encounter not found." });
    const count = encounter.participants.length;
    if (count === 0) return res.status(400).json({ error: "Encounter has no participants." });

    const direction = req.body?.direction === "previous" ? -1 : 1;
    let {round} = encounter;
    let turnIndex = encounter.turnIndex + direction;
    if (turnIndex >= count) {
      turnIndex = 0;
      round += 1;
    } else if (turnIndex < 0) {
      turnIndex = count - 1;
      round = Math.max(1, round - 1);
    }

    // ── Condition expiry & death saves ──
    // If advancing forward (not previous), process the previous participant's conditions
    if (direction === 1) {
      const previousParticipant = encounter.participants[encounter.turnIndex];
      if (previousParticipant) {
        const conditions = parseJson(previousParticipant.conditions, []);
        let changed = false;

        // Decrement duration on each condition, remove expired ones
        const updated = conditions
          .map((c) => {
            if (c.duration === undefined || c.duration === null) return c; // permanent
            return { ...c, duration: c.duration - 1 };
          })
          .filter((c) => c.duration === undefined || c.duration === null || c.duration > 0);

        if (updated.length !== conditions.length) changed = true;
        // Check if any durations changed
        for (let i = 0; i < conditions.length; i++) {
          if (conditions[i].duration !== undefined && conditions[i].duration !== null &&
              updated[i] && updated[i].duration !== conditions[i].duration - 1) {
            changed = true;
            break;
          }
        }

        if (changed) {
          await prisma.encounterParticipant.update({
            where: { id: previousParticipant.id },
            data: { conditions: JSON.stringify(updated) },
          });
        }
      }
    }

    // ── Auto death save on 0 HP (for the next participant whose turn it becomes) ──
    if (direction === 1) {
      const nextParticipant = encounter.participants[turnIndex];
      if (nextParticipant && nextParticipant.currentHp === 0) {
        const deathSaves = parseJson(nextParticipant.deathSaves, { successes: 0, failures: 0, isStable: false });
        if (!deathSaves.isStable) {
          // Auto-fail: at 0 HP, each turn start = 1 failed death save
          deathSaves.failures = Math.min(deathSaves.failures + 1, 3);
          await prisma.encounterParticipant.update({
            where: { id: nextParticipant.id },
            data: { deathSaves: JSON.stringify(deathSaves) },
          });
        }
      }
    }

    await prisma.encounter.update({
      where: { id: encounter.id },
      data: { round, turnIndex },
    });
    await respondEncounter(req, res, encounter.id);
  } catch (err) {
    logger.error("api:route", "Error in POST /api/encounters/:id/turn", { error: err.message });
    res.status(500).json({ error: "Failed to advance turn." });
  }
});

// ---------------------------------------------------------------------------
// POST /:id/suggest-action — AI Combat Tactician
// Suggests tactical actions for a specific encounter participant
// ---------------------------------------------------------------------------
router.post("/:id/suggest-action", requireDm, async (req, res) => {
  try {
    const encounterId = Number(req.params.id);
    const participantId = Number(req.body?.participantId);

    if (!Number.isInteger(participantId) || participantId <= 0) {
      return res.status(400).json({ error: "A valid participantId is required." });
    }

    const encounter = await fetchEncounter(encounterId);
    if (!encounter) return res.status(404).json({ error: "Encounter not found." });

    const participant = encounter.participants.find(p => p.id === participantId);
    if (!participant) return res.status(404).json({ error: "Participant not found." });

    // Build statblock context
    let statblock = {};
    let actions = [];

    if (participant.monster) {
      statblock = participant.monster;
      const rawActions = parseJson(participant.monster.actions, []);
      actions = rawActions.map(a => `${a.name}: ${a.description}${a.toHit ? ` (hit: +${a.toHit})` : ""}${a.damage ? ` (damage: ${a.damage})` : ""}`);
    } else if (participant.npc) {
      statblock = participant.npc;
      const rawActions = parseJson(participant.npc.actions, []);
      actions = rawActions.map(a => `${a.name}: ${a.description}${a.toHit ? ` (hit: +${a.toHit})` : ""}${a.damage ? ` (damage: ${a.damage})` : ""}`);
    } else if (participant.character) {
      statblock = participant.character;
      actions = ["Unarmed Strike", "Improvised Weapon", "Dash", "Dodge", "Help", "Hide"];
    }

    // Build encounter state summary
    const allParticipants = encounter.participants.map(p => ({
      name: p.name,
      initiative: p.initiative,
      hp: `${p.currentHp}/${p.maxHp}`,
      ac: p.ac,
      conditions: parseJson(p.conditions, []).map(c => c.name),
      isCurrentTurn: p.id === participantId,
      source: p.source || (p.npcId ? "npc" : p.monsterId ? "monster" : p.characterId ? "character" : "unknown"),
    }));

    const { performAiCall, loadAiSettings } = require("../ai/helpers");
    const aiSettings = await loadAiSettings();
    const { provider, apiKey, ollamaUrl, ollamaModel, model } = aiSettings;
    const activeModel = provider === "opencode" ? (model || "gpt-5-nano") : ollamaModel;

    if (!provider) {
      // Fallback: simple heuristic-based suggestion
      const hpPercent = participant.currentHp / Math.max(1, participant.maxHp);
      const intelligent = !!(participant.npc?.intelligence > 10 || participant.monster);
      const fallback = { recommended: "", alternatives: [] };

      if (hpPercent < 0.3) {
        fallback.recommended = "Flee or retreat — the creature is bloodied and would seek safety";
        if (intelligent) {
          fallback.alternatives.push("Use a defensive action: Dodge or cast a protective spell");
        }
      } else if (actions.length > 0) {
        fallback.recommended = "Use Multiattack or primary action against the nearest visible threat";
        fallback.alternatives.push("Use a special ability if available");
        if (actions.length > 1) {
          fallback.alternatives.push(`Try ${actions[1]}`);
        }
      } else {
        fallback.recommended = "Attack the nearest enemy combatant";
        fallback.alternatives.push("Use the Help action to assist an ally");
      }

      return res.json(fallback);
    }

    const systemPrompt = `You are an AI Combat Tactician for Dungeons & Dragons 5th Edition.
Given an encounter participant's statblock and the current combat state, suggest 1-3 tactical actions.
Consider: target prioritization (low HP, concentrating, highest threat), positioning, resource economy (limited-use abilities), and creature intelligence.
Return JSON only (no markdown): { "recommended": "action description with reasoning", "alternatives": ["alt 1", "alt 2"] }`;

    const userMessage = `Current encounter state (all participants):
${JSON.stringify(allParticipants, null, 2)}

This participant's statblock:
${JSON.stringify(statblock, null, 2)}

Available actions:
${actions.length > 0 ? actions.join("\n") : "No special actions available — use standard actions"}

Current HP: ${participant.currentHp}/${participant.maxHp}
Current AC: ${participant.ac}
Conditions: ${JSON.stringify(parseJson(participant.conditions, []).map(c => c.name))}

Suggest tactical actions for ${participant.name}.`;

    const rawResult = await performAiCall(provider, apiKey, ollamaUrl, activeModel, systemPrompt, userMessage, [], "combat-tactician");

    // Parse JSON from response
    let cleanJson = rawResult.trim();
    if (cleanJson.startsWith("```")) {
      const match = cleanJson.match(/```(?:json)?([\s\S]+?)```/);
      if (match) cleanJson = match[1].trim();
    }

    const result = JSON.parse(cleanJson);
    res.json({
      recommended: result.recommended || "Attack the nearest enemy",
      alternatives: result.alternatives || [],
    });
  } catch (err) {
    if (err.code === "P2025") return res.status(404).json({ error: "Encounter not found." });
    logger.error("api:route", "Error in POST /api/encounters/:id/suggest-action", { error: err.message });
    res.status(500).json({ error: err.message });
  }
});

module.exports = router;

// =============================================================================
// Tablecast  Homebrew Entry CRUD Routes
// Endpoints:  GET    /api/homebrew              (?type= & ?active=)
//             GET    /api/homebrew/:id
//             POST   /api/homebrew
//             PUT    /api/homebrew/:id
//             DELETE /api/homebrew/:id
//             POST   /api/homebrew/export
//             POST   /api/homebrew/import
// =============================================================================
"use strict";

const { Router } = require("express");
const prisma = require("../prisma");
const { getRequestUser, requireDm } = require("../auth");
const logger = require("../utils/logger");

const router = Router();

const VALID_TYPES = new Set(["RACE", "CLASS", "FEAT", "SPELL", "MAGIC_ITEM", "MONSTER"]);

function parseJsonArray(value) {
  try {
    const parsed = JSON.parse(value || "[]");
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function parseJsonObject(value) {
  try {
    const parsed = JSON.parse(value || "{}");
    return (parsed && typeof parsed === "object") ? parsed : {};
  } catch {
    return {};
  }
}

function formatEntry(e) {
  return {
    ...e,
    content: parseJsonObject(e.content),
    tags: parseJsonArray(e.tags),
  };
}

// ---------------------------------------------------------------------------
// GET /api/homebrew  list all homebrew entries
// Query params: ?type=RACE  filter by type, ?active=true
// ---------------------------------------------------------------------------
router.get("/", async (req, res) => {
  try {
    const where = {};
    if (req.query.type) {
      const type = String(req.query.type).toUpperCase();
      if (!VALID_TYPES.has(type)) {
        return res.status(400).json({ error: `type must be one of: ${[...VALID_TYPES].join(", ")}` });
      }
      where.type = type;
    }
    if (req.query.active === "true") {
      where.isActive = true;
    }

    const entries = await prisma.homebrewEntry.findMany({
      where,
      orderBy: { updatedAt: "desc" },
    });

    res.json(entries.map(formatEntry));
  } catch (err) {
    logger.error("api:route", "Error in GET /api/homebrew", { error: err.message });
    res.status(500).json({ error: "Failed to fetch homebrew entries." });
  }
});

// ---------------------------------------------------------------------------
// GET /api/homebrew/:id  get a single homebrew entry
// ---------------------------------------------------------------------------
router.get("/:id", async (req, res) => {
  try {
    const id = Number(req.params.id);
    if (isNaN(id)) {
      return res.status(400).json({ error: "id must be a valid number." });
    }

    const entry = await prisma.homebrewEntry.findUnique({ where: { id } });
    if (!entry) {
      return res.status(404).json({ error: "Homebrew entry not found." });
    }

    res.json(formatEntry(entry));
  } catch (err) {
    logger.error("api:route", "Error in GET /api/homebrew/:id", { error: err.message });
    res.status(500).json({ error: "Failed to fetch homebrew entry." });
  }
});

// ---------------------------------------------------------------------------
// POST /api/homebrew  create a new homebrew entry (DM only)
// Body: { type, name, source?, version?, content?, tags?, isActive? }
// ---------------------------------------------------------------------------
router.post("/", requireDm, async (req, res) => {
  try {
    const { type, name, source, version, content, tags, isActive } = req.body;

    if (!type || !VALID_TYPES.has(String(type).toUpperCase())) {
      return res.status(400).json({ error: `type must be one of: ${[...VALID_TYPES].join(", ")}` });
    }
    if (!name || typeof name !== "string" || !name.trim()) {
      return res.status(400).json({ error: "name is required." });
    }

    const data = {
      type: String(type).toUpperCase(),
      name: name.trim(),
      source: source || "",
      version: version || "1.0.0",
      content: content !== undefined ? JSON.stringify(content) : "{}",
      tags: tags !== undefined ? JSON.stringify(tags) : "[]",
      isActive: isActive !== false,
    };

    const entry = await prisma.homebrewEntry.create({ data });
    res.status(201).json(formatEntry(entry));
  } catch (err) {
    logger.error("api:route", "Error in POST /api/homebrew", { error: err.message });
    res.status(500).json({ error: "Failed to create homebrew entry." });
  }
});

// ---------------------------------------------------------------------------
// PUT /api/homebrew/:id  update a homebrew entry (DM only)
// ---------------------------------------------------------------------------
router.put("/:id", requireDm, async (req, res) => {
  try {
    const id = Number(req.params.id);
    if (isNaN(id)) {
      return res.status(400).json({ error: "id must be a valid number." });
    }

    const { type, name, source, version, content, tags, isActive } = req.body;
    const data = {};

    if (type !== undefined) {
      const t = String(type).toUpperCase();
      if (!VALID_TYPES.has(t)) {
        return res.status(400).json({ error: `type must be one of: ${[...VALID_TYPES].join(", ")}` });
      }
      data.type = t;
    }
    if (name !== undefined) {
      if (typeof name !== "string" || !name.trim()) {
        return res.status(400).json({ error: "name must be a non-empty string." });
      }
      data.name = name.trim();
    }
    if (source !== undefined) data.source = source;
    if (version !== undefined) data.version = version;
    if (content !== undefined) data.content = JSON.stringify(content);
    if (tags !== undefined) data.tags = JSON.stringify(tags);
    if (isActive !== undefined) data.isActive = isActive === true;

    if (Object.keys(data).length === 0) {
      return res.status(400).json({ error: "No valid fields to update." });
    }

    const entry = await prisma.homebrewEntry.update({ where: { id }, data });
    res.json(formatEntry(entry));
  } catch (err) {
    if (err.code === "P2025") {
      return res.status(404).json({ error: "Homebrew entry not found." });
    }
    logger.error("api:route", "Error in PUT /api/homebrew/:id", { error: err.message });
    res.status(500).json({ error: "Failed to update homebrew entry." });
  }
});

// ---------------------------------------------------------------------------
// DELETE /api/homebrew/:id  delete a homebrew entry (DM only)
// ---------------------------------------------------------------------------
router.delete("/:id", requireDm, async (req, res) => {
  try {
    const id = Number(req.params.id);
    if (isNaN(id)) {
      return res.status(400).json({ error: "id must be a valid number." });
    }

    await prisma.homebrewEntry.delete({ where: { id } });
    res.json({ message: "Homebrew entry deleted." });
  } catch (err) {
    if (err.code === "P2025") {
      return res.status(404).json({ error: "Homebrew entry not found." });
    }
    logger.error("api:route", "Error in DELETE /api/homebrew/:id", { error: err.message });
    res.status(500).json({ error: "Failed to delete homebrew entry." });
  }
});

// ---------------------------------------------------------------------------
// POST /api/homebrew/export  export homebrew entries as JSON (DM only)
// Body: { ids?: number[] }  — omit ids to export all
// ---------------------------------------------------------------------------
router.post("/export", requireDm, async (req, res) => {
  try {
    const { ids } = req.body;
    const where = {};
    if (Array.isArray(ids) && ids.length > 0) {
      where.id = { in: ids.map(Number).filter((n) => !isNaN(n) && n > 0) };
    }

    const entries = await prisma.homebrewEntry.findMany({ where });
    const payload = {
      version: 1,
      exportedAt: new Date().toISOString(),
      source: "Tablecast Homebrew Export",
      entries: entries.map((e) => ({
        type: e.type,
        name: e.name,
        source: e.source,
        version: e.version,
        content: parseJsonObject(e.content),
        tags: parseJsonArray(e.tags),
        isActive: e.isActive,
      })),
    };

    res.json(payload);
  } catch (err) {
    logger.error("api:route", "Error in POST /api/homebrew/export", { error: err.message });
    res.status(500).json({ error: "Failed to export homebrew entries." });
  }
});

// ---------------------------------------------------------------------------
// POST /api/homebrew/import  import homebrew entries from JSON (DM only)
// Body: { entries: [...], overwrite?: boolean }
// ---------------------------------------------------------------------------
router.post("/import", requireDm, async (req, res) => {
  try {
    const { entries, overwrite } = req.body;
    if (!Array.isArray(entries) || entries.length === 0) {
      return res.status(400).json({ error: "entries must be a non-empty array." });
    }

    const results = { created: 0, updated: 0, skipped: 0, errors: [] };

    for (const entry of entries) {
      try {
        const type = String(entry.type || "").toUpperCase();
        if (!VALID_TYPES.has(type)) {
          results.errors.push(`Invalid type "${entry.type}" for "${entry.name}"`);
          continue;
        }
        if (!entry.name || typeof entry.name !== "string") {
          results.errors.push(`Missing name for entry with type ${type}`);
          continue;
        }

        // Check for duplicate by name + type
        const existing = await prisma.homebrewEntry.findFirst({
          where: { name: entry.name.trim(), type },
        });

        if (existing) {
          if (overwrite === true) {
            await prisma.homebrewEntry.update({
              where: { id: existing.id },
              data: {
                source: entry.source || existing.source,
                version: entry.version || existing.version,
                content: entry.content ? JSON.stringify(entry.content) : existing.content,
                tags: entry.tags ? JSON.stringify(entry.tags) : existing.tags,
                isActive: entry.isActive !== false,
              },
            });
            results.updated++;
          } else {
            results.skipped++;
          }
        } else {
          await prisma.homebrewEntry.create({
            data: {
              type,
              name: entry.name.trim(),
              source: entry.source || "",
              version: entry.version || "1.0.0",
              content: entry.content ? JSON.stringify(entry.content) : "{}",
              tags: entry.tags ? JSON.stringify(entry.tags) : "[]",
              isActive: entry.isActive !== false,
            },
          });
          results.created++;
        }
      } catch (err) {
        results.errors.push(`Error processing "${entry.name}": ${err.message}`);
      }
    }

    res.json(results);
  } catch (err) {
    logger.error("api:route", "Error in POST /api/homebrew/import", { error: err.message });
    res.status(500).json({ error: "Failed to import homebrew entries." });
  }
});

module.exports = router;

// =============================================================================
// Tablecast  Loot Generator Routes
// Endpoints:  POST   /api/loot/generate              — Generate loot
//             GET    /api/loot/cache                  — List unclaimed loot
//             POST   /api/loot/cache/:id/assign       — Assign to party
//             DELETE /api/loot/cache/:id              — Discard cache
// =============================================================================
"use strict";

const { Router } = require("express");
const prisma = require("../prisma");
const { requireDm, getRequestUser } = require("../auth");
const logger = require("../utils/logger");
const {
  generateIndividualTreasure,
  generateHoardTreasure,
  calculateTotalValue,
  getCrTier,
} = require("../utils/treasureTables");

const router = Router();

// ---------------------------------------------------------------------------
// Helper: Parse JSON safely
// ---------------------------------------------------------------------------
function parseJson(value, fallback = {}) {
  try {
    return JSON.parse(value || "{}");
  } catch {
    return fallback;
  }
}

function parseJsonArray(value, fallback = []) {
  try {
    const parsed = JSON.parse(value || "[]");
    return Array.isArray(parsed) ? parsed : fallback;
  } catch {
    return fallback;
  }
}

/**
 * Format a loot cache record for API response.
 */
function formatCache(c) {
  return {
    ...c,
    data: parseJson(c.data),
  };
}

// ---------------------------------------------------------------------------
// POST /api/loot/generate — Generate loot
// Body: { cr: number|string, type: "individual"|"hoard"|"both", label?: string }
// ---------------------------------------------------------------------------
router.post("/generate", requireDm, async (req, res) => {
  try {
    const { cr, type = "individual", label } = req.body;

    if (cr === undefined || cr === null) {
      return res.status(400).json({ error: "cr (challenge rating) is required." });
    }

    const tier = getCrTier(cr);
    let result;

    if (type === "individual" || type === "both") {
      result = generateIndividualTreasure(cr);
      result.type = "individual";
      result.tier = tier;
    }

    if (type === "hoard" || type === "both") {
      const hoard = generateHoardTreasure(cr);
      hoard.type = "hoard";
      hoard.tier = tier;

      if (type === "both") {
        result = {
          type: "both",
          tier,
          individual: result,
          hoard,
          totalValue: calculateTotalValue(result) + calculateTotalValue(hoard),
        };
      } else {
        result = hoard;
      }
    }

    if (!result) {
      result = generateIndividualTreasure(cr);
      result.type = "individual";
      result.tier = tier;
    }

    // Calculate total value if not already done
    if (result.totalValue === undefined) {
      result.totalValue = calculateTotalValue(result);
    }

    // Add label
    result.label = label || `CR ${cr} ${type === "both" ? "Treasure" : type === "hoard" ? "Hoard" : "Individual Treasure"}`;
    result.cr = cr;

    res.json(result);
  } catch (err) {
    logger.error("api:loot", "Error in POST /api/loot/generate", { error: err.message });
    res.status(500).json({ error: "Failed to generate loot." });
  }
});

// ---------------------------------------------------------------------------
// POST /api/loot/cache — Save generated loot as unclaimed cache
// Body: { data: object } — the loot generation result
// ---------------------------------------------------------------------------
router.post("/cache", requireDm, async (req, res) => {
  try {
    const { data } = req.body;
    if (!data) {
      return res.status(400).json({ error: "data (loot generation result) is required." });
    }
    const cache = await prisma.lootCache.create({
      data: {
        data: JSON.stringify(data),
      },
    });
    res.status(201).json(formatCache(cache));
  } catch (err) {
    logger.error("api:loot", "Error in POST /api/loot/cache", { error: err.message });
    res.status(500).json({ error: "Failed to cache loot." });
  }
});

// ---------------------------------------------------------------------------
// GET /api/loot/cache — List unclaimed loot caches
// ---------------------------------------------------------------------------
router.get("/cache", requireDm, async (req, res) => {
  try {
    const caches = await prisma.lootCache.findMany({
      orderBy: { createdAt: "desc" },
    });
    res.json(caches.map(formatCache));
  } catch (err) {
    logger.error("api:loot", "Error in GET /api/loot/cache", { error: err.message });
    res.status(500).json({ error: "Failed to list loot caches." });
  }
});

// ---------------------------------------------------------------------------
// POST /api/loot/cache/:id/assign — Assign cached loot to a party
// Body: { partyId: number }
// ---------------------------------------------------------------------------
router.post("/cache/:id/assign", requireDm, async (req, res) => {
  try {
    const id = Number(req.params.id);
    const { partyId } = req.body;

    if (!partyId) {
      return res.status(400).json({ error: "partyId is required." });
    }

    // Fetch the loot cache
    const cache = await prisma.lootCache.findUnique({ where: { id } });
    if (!cache) {
      return res.status(404).json({ error: "Loot cache not found." });
    }

    // Fetch the party
    const party = await prisma.party.findUnique({ where: { id: partyId } });
    if (!party) {
      return res.status(404).json({ error: "Party not found." });
    }

    const data = parseJson(cache.data);
    const partyInventory = parseJsonArray(party.inventory);
    const partyCurrency = parseJson(party.currency);

    // Add coins to party currency
    if (data.coins) {
      partyCurrency.pp = (partyCurrency.pp || 0) + (data.coins.pp || 0);
      partyCurrency.gp = (partyCurrency.gp || 0) + (data.coins.gp || 0);
      partyCurrency.ep = (partyCurrency.ep || 0) + (data.coins.ep || 0);
      partyCurrency.sp = (partyCurrency.sp || 0) + (data.coins.sp || 0);
      partyCurrency.cp = (partyCurrency.cp || 0) + (data.coins.cp || 0);
    }

    // Add gems to inventory
    const gems = data.gems || [];
    for (const gem of gems) {
      partyInventory.push({
        name: gem.name,
        quantity: 1,
        weight: 0,
        description: `Gemstone worth ${gem.value} gp`,
        type: "gem",
        value: gem.value,
      });
    }

    // Add art objects to inventory
    const art = data.art || [];
    for (const a of art) {
      partyInventory.push({
        name: a.name,
        quantity: 1,
        weight: 0,
        description: `Art object worth ${a.value} gp`,
        type: "art",
        value: a.value,
      });
    }

    // Add magic items to inventory
    const magicItems = data.magicItems || [];
    for (const item of magicItems) {
      partyInventory.push({
        name: item.name,
        quantity: 1,
        weight: 1,
        description: item.consumable ? "Consumable magic item" : "Magic item",
        type: "magic_item",
        consumable: item.consumable || false,
      });
    }

    // Update party
    await prisma.party.update({
      where: { id: partyId },
      data: {
        inventory: JSON.stringify(partyInventory),
        currency: JSON.stringify(partyCurrency),
      },
    });

    // Delete the loot cache after assigning
    await prisma.lootCache.delete({ where: { id } });

    // Return updated party
    const updatedParty = await prisma.party.findUnique({
      where: { id: partyId },
      include: {
        members: {
          include: {
            character: {
              select: { id: true, name: true, race: true, class: true, level: true, gold: true },
            },
          },
        },
      },
    });

    res.json({
      success: true,
      message: `Loot assigned to party "${party.name}". ${magicItems.length} magic item(s), ${gems.length} gem(s), ${art.length} art object(s), and coins transferred.`,
      party: updatedParty,
    });
  } catch (err) {
    logger.error("api:loot", "Error in POST /api/loot/cache/:id/assign", { error: err.message });
    res.status(500).json({ error: "Failed to assign loot to party." });
  }
});

// ---------------------------------------------------------------------------
// DELETE /api/loot/cache/:id — Discard a loot cache
// ---------------------------------------------------------------------------
router.delete("/cache/:id", requireDm, async (req, res) => {
  try {
    const id = Number(req.params.id);
    await prisma.lootCache.delete({ where: { id } });
    res.json({ success: true, message: "Loot cache discarded." });
  } catch (err) {
    logger.error("api:loot", "Error in DELETE /api/loot/cache/:id", { error: err.message });
    res.status(500).json({ error: "Failed to discard loot cache." });
  }
});

module.exports = router;

// =============================================================================
// Tablecast  Maps & Tokens CRUD Routes
// Endpoints:  GET /api/maps
//             GET /api/maps/:id
//             POST /api/maps            (supports Base64 imageData upload)
//             DELETE /api/maps/:id
//             POST /api/maps/:id/tokens
//             PUT /api/tokens/:id
//             DELETE /api/tokens/:id
// =============================================================================
"use strict";

const { Router } = require("express");
const fs = require("fs");
const path = require("path");
const prisma = require("../prisma");
const { requireDm } = require("../auth");
const logger = require("../utils/logger");

const router = Router();

// Ensure the uploads directory exists on host/container
const UPLOADS_DIR = path.join(__dirname, "../../uploads");
if (!fs.existsSync(UPLOADS_DIR)) {
  fs.mkdirSync(UPLOADS_DIR, { recursive: true });
}

// ---------------------------------------------------------------------------
// GET /api/maps  List all maps
// ---------------------------------------------------------------------------
router.get("/", requireDm, async (req, res) => {
  try {
    const maps = await prisma.map.findMany({
      orderBy: { createdAt: "asc" },
    });
    res.json(maps);
  } catch (err) {
    logger.error("api:route", "Error in GET /api/maps", { error: err.message });
    res.status(500).json({ error: "Failed to fetch maps." });
  }
});

// ---------------------------------------------------------------------------
// GET /api/maps/:id  Fetch single map with tokens
// ---------------------------------------------------------------------------
router.get("/:id", requireDm, async (req, res) => {
  try {
    const id = Number(req.params.id);
    if (isNaN(id)) {
      return res.status(400).json({ error: "id must be a valid number." });
    }

    const map = await prisma.map.findUnique({
      where: { id },
      include: { tokens: { include: { character: true, npc: true, monster: true } } },
    });

    if (!map) {
      return res.status(404).json({ error: "Map not found." });
    }

    res.json(map);
  } catch (err) {
    logger.error("api:route", "Error in GET /api/maps/:id", { error: err.message });
    res.status(500).json({ error: "Failed to fetch map." });
  }
});

// ---------------------------------------------------------------------------
// POST /api/maps  Create a map (and write Base64 image to uploads)
// Body: { name, gridSize, gridType, imageData, imageUrl }
// ---------------------------------------------------------------------------
router.post("/", requireDm, async (req, res) => {
  try {
    const { name, gridSize, gridType, imageData, imageUrl } = req.body;

    if (!name || typeof name !== "string" || !name.trim()) {
      return res.status(400).json({ error: "Map name is required." });
    }

    let resolvedImageUrl = "/uploads/placeholder_map.png";

    if (imageData && typeof imageData === "string" && imageData.startsWith("data:")) {
      const matches = imageData.match(/^data:([A-Za-z-+\/]+);base64,(.+)$/);
      if (matches && matches.length === 3) {
        const mimeType = matches[1];
        const base64Data = matches[2];
        const dataBuffer = Buffer.from(base64Data, "base64");

        // Enforce decoded image size cap (10MB)
        if (dataBuffer.length > 10 * 1024 * 1024) {
          return res.status(400).json({ error: "Image too large. Maximum decoded size is 10MB." });
        }

        // Validate image magic bytes
        const magicBytes = dataBuffer.slice(0, 4).toString("hex").toUpperCase();
        const VALID_MAGIC = new Set(["89504E47", "FFD8FFE0", "FFD8FFE1", "FFD8FFDB", "52494646", "47494638"]);
        if (!VALID_MAGIC.has(magicBytes) && !magicBytes.startsWith("FFD8FF")) {
          return res.status(400).json({ error: "Invalid image format. Only PNG, JPEG, WEBP, and GIF are allowed." });
        }

        // Determine extension
        let ext = "png";
        if (mimeType.includes("jpeg") || mimeType.includes("jpg")) ext = "jpg";
        else if (mimeType.includes("webp")) ext = "webp";
        else if (mimeType.includes("gif")) ext = "gif";

        const filename = `map_${Date.now()}_${Math.random().toString(36).slice(2, 8)}.${ext}`;
        const filePath = path.join(UPLOADS_DIR, filename);

        // Write the decoded buffer to file
        await fs.promises.writeFile(filePath, dataBuffer);
        resolvedImageUrl = `/uploads/${filename}`;
        logger.debug("api:route", "Saved uploaded map image", { filePath });
      } else {
        return res.status(400).json({ error: "Invalid base64 image data format." });
      }
    } else if (imageUrl && typeof imageUrl === "string") {
      const trimmedImageUrl = imageUrl.trim();
      const isAllowedRemotePath = /^https?:\/\/\S+$/i.test(trimmedImageUrl);

      // Validate local paths with path.resolve to prevent traversal
      if (trimmedImageUrl.startsWith("/uploads/")) {
        const resolved = path.resolve(UPLOADS_DIR, `.${trimmedImageUrl.slice("/uploads".length)}`);
        if (!resolved.startsWith(path.resolve(UPLOADS_DIR))) {
          return res.status(400).json({ error: "Invalid image URL path." });
        }
      } else if (!isAllowedRemotePath) {
        return res.status(400).json({ error: "Image URL must be an uploads path, 5etools image path, or http(s) URL." });
      }

      resolvedImageUrl = trimmedImageUrl;
    }

    const newMap = await prisma.map.create({
      data: {
        name: name.trim(),
        gridSize: gridSize ? Number(gridSize) : 50,
        gridType: gridType || "SQUARE",
        imageUrl: resolvedImageUrl,
        fogState: "[]",
        walls: req.body.walls || "[]",
      },
    });

    res.status(201).json(newMap);
  } catch (err) {
    logger.error("api:route", "Error in POST /api/maps", { error: err.message });
    res.status(500).json({ error: "Failed to create map." });
  }
});

// ---------------------------------------------------------------------------
// PATCH /api/maps/:id  Update a map (gridSize, name, etc.)
// Body: { name?, gridSize?, gridType?, walls? }
// ---------------------------------------------------------------------------
router.patch("/:id", requireDm, async (req, res) => {
  try {
    const id = Number(req.params.id);
    if (isNaN(id)) {
      return res.status(400).json({ error: "id must be a valid number." });
    }

    const data = {};
    if (req.body.name !== undefined) data.name = String(req.body.name).trim();
    if (req.body.gridSize !== undefined) data.gridSize = Math.max(20, Math.min(200, Number(req.body.gridSize)));
    if (req.body.gridType !== undefined) data.gridType = req.body.gridType;
    if (req.body.walls !== undefined) data.walls = req.body.walls;
    if (req.body.fogState !== undefined) data.fogState = req.body.fogState;

    const updated = await prisma.map.update({
      where: { id },
      data,
    });

    res.json(updated);
  } catch (err) {
    if (err.code === "P2025") {
      return res.status(404).json({ error: "Map not found." });
    }
    logger.error("api:route", "Error in PATCH /api/maps/:id", { error: err.message });
    res.status(500).json({ error: "Failed to update map." });
  }
});

// ---------------------------------------------------------------------------
// DELETE /api/maps/:id  Delete a map
// ---------------------------------------------------------------------------
router.delete("/:id", requireDm, async (req, res) => {
  try {
    const mapId = Number(req.params.id);
    if (isNaN(mapId) || mapId <= 0) {
      return res.status(400).json({ error: "Invalid map id." });
    }

    // Find first to delete actual image from filesystem if it exists
    const map = await prisma.map.findUnique({ where: { id: mapId } });
    if (!map) {
      return res.status(404).json({ error: "Map not found." });
    }

    // Attempt to delete physical file if it's not a generic placeholder
    if (map.imageUrl && map.imageUrl.startsWith("/uploads/map_")) {
      const filename = path.basename(map.imageUrl);
      const filePath = path.join(UPLOADS_DIR, filename);
      try {
        await fs.promises.unlink(filePath);
        logger.debug("api:route", "Deleted map image file", { filePath });
      } catch (fileErr) {
        if (fileErr.code !== "ENOENT") {
          logger.error("api:route", "Error deleting map image file", { error: fileErr.message, filePath });
        }
      }
    }

    await prisma.map.delete({ where: { id: mapId } });
    res.json({ message: "Map deleted successfully." });
  } catch (err) {
    logger.error("api:route", "Error in DELETE /api/maps/:id", { error: err.message });
    res.status(500).json({ error: "Failed to delete map." });
  }
});

// ---------------------------------------------------------------------------
// POST /api/maps/:id/tokens  Add a token to a map
// Body: { characterId, label, imageUrl, x, y }
// ---------------------------------------------------------------------------
router.post("/:id/tokens", requireDm, async (req, res) => {
  try {
    const mapId = Number(req.params.id);
    const { characterId, npcId, monsterId, label, imageUrl, x, y, stats } = req.body;
    const tokenX = x !== undefined ? Number(x) : 0;
    const tokenY = y !== undefined ? Number(y) : 0;

    if (isNaN(mapId) || mapId <= 0) {
      return res.status(400).json({ error: "Invalid map id." });
    }

    if (!Number.isFinite(tokenX) || !Number.isFinite(tokenY) || tokenX < 0 || tokenY < 0 || tokenX > 10000 || tokenY > 10000) {
      return res.status(400).json({ error: "Token coordinates must be valid numbers between 0 and 10000." });
    }

    // Validate stats is valid JSON if provided
    let parsedStats = stats || null;
    if (stats !== undefined && stats !== null) {
      try {
        JSON.parse(stats);
        parsedStats = typeof stats === "string" ? stats : JSON.stringify(stats);
      } catch {
        return res.status(400).json({ error: "stats must be a valid JSON string." });
      }
    }

    const data = {
      mapId,
      label: label || "",
      imageUrl: imageUrl || "",
      x: tokenX,
      y: tokenY,
      stats: parsedStats,
      conditions: req.body.conditions || "[]",
      visionRadius: Number(req.body.visionRadius) || 0,
      darkvisionRadius: Number(req.body.darkvisionRadius) || 0,
      auraRadius: Number(req.body.auraRadius) || 0,
      auraColor: String(req.body.auraColor || ""),
    };

    if (characterId) {
      data.characterId = Number(characterId);
    }
    if (npcId) {
      data.npcId = Number(npcId);
    }
    if (monsterId) {
      data.monsterId = Number(monsterId);
    }

    const token = await prisma.token.create({
      data,
      include: { character: true, npc: true, monster: true },
    });

    res.status(201).json(token);
  } catch (err) {
    if (err.code === "P2025") {
      return res.status(404).json({ error: "Map not found." });
    }
    logger.error("api:route", "Error in POST /api/maps/:id/tokens", { error: err.message });
    res.status(500).json({ error: "Failed to create token." });
  }
});

// ---------------------------------------------------------------------------
// PUT /api/tokens/:id  Update token (label, imageUrl, characterId, x, y)
// ---------------------------------------------------------------------------
router.put("/tokens/:id", requireDm, async (req, res) => {
  try {
    const tokenId = Number(req.params.id);
    const { characterId, npcId, monsterId, label, imageUrl, x, y, stats } = req.body;
    if (isNaN(tokenId) || tokenId <= 0) {
      return res.status(400).json({ error: "Invalid token id." });
    }

    const data = {};
    if (label !== undefined) data.label = label;
    if (imageUrl !== undefined) data.imageUrl = imageUrl;
    if (x !== undefined) {
      const nextX = Number(x);
      if (!Number.isFinite(nextX) || nextX < 0 || nextX > 10000) {
        return res.status(400).json({ error: "Token x coordinate must be between 0 and 10000." });
      }
      data.x = nextX;
    }
    if (y !== undefined) {
      const nextY = Number(y);
      if (!Number.isFinite(nextY) || nextY < 0 || nextY > 10000) {
        return res.status(400).json({ error: "Token y coordinate must be between 0 and 10000." });
      }
      data.y = nextY;
    }
    if (characterId !== undefined) data.characterId = characterId ? Number(characterId) : null;
    if (npcId !== undefined) data.npcId = npcId ? Number(npcId) : null;
    if (monsterId !== undefined) data.monsterId = monsterId ? Number(monsterId) : null;
    // VTT feature fields: conditions, vision, aura
    if (req.body.conditions !== undefined) data.conditions = req.body.conditions;
    if (req.body.visionRadius !== undefined) data.visionRadius = Number(req.body.visionRadius) || 0;
    if (req.body.darkvisionRadius !== undefined) data.darkvisionRadius = Number(req.body.darkvisionRadius) || 0;
    if (req.body.auraRadius !== undefined) data.auraRadius = Number(req.body.auraRadius) || 0;
    if (req.body.auraColor !== undefined) data.auraColor = String(req.body.auraColor || "");
    if (stats !== undefined) {
      try {
        JSON.parse(typeof stats === "string" ? stats : JSON.stringify(stats));
        data.stats = typeof stats === "string" ? stats : JSON.stringify(stats);
      } catch {
        return res.status(400).json({ error: "stats must be a valid JSON string." });
      }
    }

    // Direct HP sync: if this token is linked to an NPC or Monster and stats are updated with a currentHp,
    // update the NPC's or Monster's HP in the database too.
    const existingToken = await prisma.token.findUnique({
      where: { id: tokenId },
      select: { npcId: true, monsterId: true },
    });
    if (existingToken?.npcId && stats) {
      try {
        const parsedStats = JSON.parse(stats);
        if (parsedStats.currentHp !== undefined) {
          await prisma.npc.update({
            where: { id: existingToken.npcId },
            data: { hp: Math.max(0, Number(parsedStats.currentHp)) },
          });
        }
      } catch (err) {
        logger.error("api:route", "Error syncing NPC health from token stats", { error: err.message });
      }
    }
    if (existingToken?.monsterId && stats) {
      try {
        const parsedStats = JSON.parse(stats);
        if (parsedStats.currentHp !== undefined) {
          await prisma.monster.update({
            where: { id: existingToken.monsterId },
            data: { hp: Math.max(0, Number(parsedStats.currentHp)) },
          });
        }
      } catch (err) {
        logger.error("api:route", "Error syncing Monster health from token stats", { error: err.message });
      }
    }

    const updatedToken = await prisma.token.update({
      where: { id: tokenId },
      data,
      include: { character: true, npc: true, monster: true },
    });

    res.json(updatedToken);
  } catch (err) {
    if (err.code === "P2025") {
      return res.status(404).json({ error: "Token not found." });
    }
    logger.error("api:route", "Error in PUT /api/tokens/:id", { error: err.message });
    res.status(500).json({ error: "Failed to update token." });
  }
});

// ---------------------------------------------------------------------------
// DELETE /api/tokens/:id  Delete token
// ---------------------------------------------------------------------------
router.delete("/tokens/:id", requireDm, async (req, res) => {
  try {
    const tokenId = Number(req.params.id);
    if (isNaN(tokenId) || tokenId <= 0) {
      return res.status(400).json({ error: "Invalid token id." });
    }
    await prisma.token.delete({ where: { id: tokenId } });
    res.json({ message: "Token deleted successfully." });
  } catch (err) {
    if (err.code === "P2025") {
      return res.status(404).json({ error: "Token not found." });
    }
    logger.error("api:route", "Error in DELETE /api/tokens/:id", { error: err.message });
    res.status(500).json({ error: "Failed to delete token." });
  }
});

module.exports = router;

