// =============================================================================
// Tablecast — Dialogue Tree Engine
// Utility for navigating, evaluating conditions, and executing actions in
// NPC dialogue trees.
// =============================================================================
"use strict";

/**
 * Resolve a node by its ID from a dialogue tree.
 * @param {object} tree - The dialogue tree object { startNodeId, nodes }
 * @param {string} nodeId - The node ID to find
 * @returns {object|null} The matching node, or null if not found
 */
function resolveNode(tree, nodeId) {
  if (!tree || !tree.nodes || !Array.isArray(tree.nodes)) return null;
  return tree.nodes.find(n => n.id === nodeId) || null;
}

/**
 * Get the starting node of a dialogue tree.
 * @param {object} tree - The dialogue tree object
 * @returns {object|null} The starting node, or null if invalid
 */
function getStartNode(tree) {
  if (!tree || !tree.startNodeId || !tree.nodes) return null;
  return resolveNode(tree, tree.startNodeId);
}

/**
 * Evaluate a simple condition expression against a context object.
 * Supports expressions like:
 *   "party.gold >= 100"
 *   "player.hasItem('key')"
 *   "roll >= 15"
 *   "variable == value"
 * @param {string} condition - The condition expression string
 * @param {object} context - Evaluation context { party, player, variables, roll }
 * @returns {boolean} The result of evaluation
 */
function evaluateCondition(condition, context = {}) {
  if (!condition) return true;

  // Build evaluation context with defaults
  const party = context.party || { gold: 0 };
  const player = context.player || { level: 1, hasItem: () => false };
  const variables = context.variables || {};
  const roll = context.roll || 0;

  try {
    // Use Function constructor for safe evaluation with limited scope
    const fn = new Function(
      "party", "player", "variables", "roll",
      `"use strict"; return (${condition});`
    );
    return !!fn(party, player, variables, roll);
  } catch {
    return false;
  }
}

/**
 * Execute a dialogue action and return a result descriptor.
 * @param {string} actionType - The action type (give_item, remove_item, etc.)
 * @param {string|object} actionPayload - JSON string or object payload
 * @param {object} context - Execution context
 * @returns {{ success: boolean, message: string }} Action result
 */
function executeAction(actionType, actionPayload, _context = {}) {
  let payload;
  if (typeof actionPayload === "string") {
    try {
      payload = JSON.parse(actionPayload || "{}");
    } catch {
      payload = {};
    }
  } else {
    payload = actionPayload || {};
  }

  switch (actionType) {
    case "give_item":
      return { success: true, message: `Gave ${payload.quantity || 1}x ${payload.item || "unknown item"} to party.` };
    case "remove_item":
      return { success: true, message: `Removed ${payload.quantity || 1}x ${payload.item || "unknown item"} from party.` };
    case "give_gold":
      return { success: true, message: `Party received ${payload.amount || 0} gold.` };
    case "remove_gold":
      return { success: true, message: `Party lost ${payload.amount || 0} gold.` };
    case "start_encounter":
      return { success: true, message: `Starting encounter: ${payload.encounterName || "Unknown"}` };
    case "set_variable":
      return { success: true, message: `Variable ${payload.name || "unknown"} set to ${payload.value}.` };
    case "send_message":
      return { success: true, message: payload.message || "Message sent." };
    case "custom":
      return { success: true, message: payload.message || "Custom action executed." };
    default:
      return { success: false, message: `Unknown action type: ${actionType}` };
  }
}

/**
 * Pick a random choice from a RANDOM node based on weights.
 * @param {Array} choices - Array of choice objects with weight and nextNodeId
 * @returns {object|null} The selected choice, or null if empty
 */
function pickWeightedRandom(choices) {
  if (!choices || choices.length === 0) return null;
  const totalWeight = choices.reduce((sum, c) => sum + (c.weight || 1), 0);
  let roll = Math.random() * totalWeight;
  for (const choice of choices) {
    roll -= choice.weight || 1;
    if (roll <= 0) return choice;
  }
  return choices[choices.length - 1];
}

module.exports = {
  resolveNode,
  getStartNode,
  evaluateCondition,
  executeAction,
  pickWeightedRandom,
};

// =============================================================================
// Tablecast  Dice Roll Detection Utility
// Scans AI-generated text for D&D 5e check patterns and returns clickable
// roll chip metadata. Used for AI-Triggered Dice Roll Integration (§6.1).
// =============================================================================
"use strict";

/**
 * Pattern definitions for D&D 5e checks, saves, and attack rolls.
 * Each pattern produces a roll chip with type, label, and optional DC.
 */
const PATTERNS = [
  // "Perception check", "Investigation check", etc.
  { regex: /\b(Strength|Dexterity|Constitution|Intelligence|Wisdom|Charisma)\s+(check|save|saving throw)\b/gi, mapType: "save" },
  // "Perception check", "Stealth check", etc. (skills)
  { regex: /\b(Acrobatics|Animal Handling|Arcana|Athletics|Deception|History|Insight|Intimidation|Investigation|Medicine|Nature|Perception|Performance|Persuasion|Religion|Sleight of Hand|Stealth|Survival)\s+(check|save)\b/gi, mapType: "skill" },
  // "saving throw" standalone
  { regex: /\bsaving throw\b/gi, mapType: "save" },
  // "DC N" or "DC N" patterns
  { regex: /\bDC\s*(\d+)\b/gi, mapType: "dc" },
  // "attack roll"
  { regex: /\battack roll\b/gi, mapType: "attack" },
  // "make a melee/ranged attack"
  { regex: /\b(melee|ranged)\s+attack\b/gi, mapType: "attack" },
  // "make a Dexterity/Strength/etc. check"
  { regex: /\b(Strength|Dexterity|Constitution|Intelligence|Wisdom|Charisma)\s+check\b/gi, mapType: "check" },
];

/**
 * Known D&D 5e skills mapped to their primary ability.
 */
const SKILL_ABILITY = {
  acrobatics: "dexterity",
  "animal handling": "wisdom",
  arcana: "intelligence",
  athletics: "strength",
  deception: "charisma",
  history: "intelligence",
  insight: "wisdom",
  intimidation: "charisma",
  investigation: "intelligence",
  medicine: "wisdom",
  nature: "intelligence",
  perception: "wisdom",
  performance: "charisma",
  persuasion: "charisma",
  religion: "intelligence",
  "sleight of hand": "dexterity",
  stealth: "dexterity",
  survival: "wisdom",
};

const SAVE_ABILITY = {
  strength: "strength",
  dexterity: "dexterity",
  constitution: "constitution",
  intelligence: "intelligence",
  wisdom: "wisdom",
  charisma: "charisma",
};

/**
 * Scan text for D&D roll patterns and return an array of chip descriptors.
 * @param {string} text - The AI response text to scan.
 * @returns {Array<{type: string, label: string, skill?: string, ability?: string, dc?: number}>}
 */
function scanTextForRollChips(text) {
  if (!text || typeof text !== "string") return [];

  const chips = [];
  const seen = new Set();

  // Find all DC values in text
  const dcMatches = [];
  const dcRegex = /\bDC\s*(\d+)\b/gi;
  let dcMatch;
  while ((dcMatch = dcRegex.exec(text)) !== null) {
    dcMatches.push(parseInt(dcMatch[1], 10));
  }
  const nearestDc = dcMatches.length > 0 ? dcMatches[0] : null;

  // Scan for skill checks
  const skillCheckRegex = /\b(Acrobatics|Animal Handling|Arcana|Athletics|Deception|History|Insight|Intimidation|Investigation|Medicine|Nature|Perception|Performance|Persuasion|Religion|Sleight of Hand|Stealth|Survival)\s+check\b/gi;
  let skillMatch;
  while ((skillMatch = skillCheckRegex.exec(text)) !== null) {
    const skill = skillMatch[1].toLowerCase();
    const key = `skill:${skill}`;
    if (!seen.has(key)) {
      seen.add(key);
      chips.push({
        type: "skill",
        label: `${skillMatch[1]} Check`,
        skill,
        ability: SKILL_ABILITY[skill] || "wisdom",
        dc: nearestDc || undefined,
      });
    }
  }

  // Scan for ability saves
  const saveRegex = /\b(Strength|Dexterity|Constitution|Intelligence|Wisdom|Charisma)\s+(save|saving throw)\b/gi;
  let saveMatch;
  while ((saveMatch = saveRegex.exec(text)) !== null) {
    const ability = saveMatch[1].toLowerCase();
    const key = `save:${ability}`;
    if (!seen.has(key)) {
      seen.add(key);
      chips.push({
        type: "save",
        label: `${saveMatch[1]} Save`,
        ability,
        dc: nearestDc || undefined,
      });
    }
  }

  // Scan for "saving throw" standalone
  if (/\bsaving throw\b/i.test(text) && !seen.has("save:generic")) {
    seen.add("save:generic");
    chips.push({
      type: "save",
      label: "Saving Throw",
      dc: nearestDc || undefined,
    });
  }

  // Scan for ability checks
  const abilityCheckRegex = /\b(Strength|Dexterity|Constitution|Intelligence|Wisdom|Charisma)\s+check\b/gi;
  let abilityMatch;
  while ((abilityMatch = abilityCheckRegex.exec(text)) !== null) {
    const ability = abilityMatch[1].toLowerCase();
    const key = `check:${ability}`;
    if (!seen.has(key)) {
      seen.add(key);
      chips.push({
        type: "check",
        label: `${abilityMatch[1]} Check`,
        ability,
        dc: nearestDc || undefined,
      });
    }
  }

  // Scan for attack rolls
  if (/\battack roll\b/i.test(text) || /\b(melee|ranged)\s+attack\b/i.test(text)) {
    if (!seen.has("attack")) {
      seen.add("attack");
      chips.push({
        type: "attack",
        label: "Attack Roll",
      });
    }
  }

  return chips;
}

/**
 * Inject dice roll chip markers into markdown text.
 * Adds inline markers like `[🎲 Roll Perception]` with data attributes.
 * @param {string} text - Markdown text to inject chips into.
 * @returns {string} Text with dice roll markers appended (for plain text mode)
 *   or modified text with inline markers (for markdown mode).
 */
function injectRollChips(text) {
  const chips = scanTextForRollChips(text);
  if (chips.length === 0) return text;

  const chipMarkers = chips
    .map((chip) => {
      const attrs = [`data-dice-roll="${chip.type}"`, `data-label="${chip.label}"`];
      if (chip.skill) attrs.push(`data-skill="${chip.skill}"`);
      if (chip.ability) attrs.push(`data-ability="${chip.ability}"`);
      if (chip.dc) attrs.push(`data-dc="${chip.dc}"`);
      return `<span class="dice-roll-chip touch-target" ${attrs.join(" ")}>🎲 ${chip.label}</span>`;
    })
    .join(" ");

  return `${text}\n\n${chipMarkers}`;
}

module.exports = {
  scanTextForRollChips,
  injectRollChips,
  SKILL_ABILITY,
  SAVE_ABILITY,
};

// =============================================================================
// Tablecast  5etools Reference Search Engine
// Fetches from https://5e.tools/data/ with disk + in-memory caching.
// =============================================================================
"use strict";

const fs = require("fs");
const path = require("path");
const { spawnSync } = require("child_process");
const logger = require("./logger");

const CACHE_DIR = path.resolve(__dirname, "../../uploads/5etools-cache");
// Base URL for 5etools raw data (GitHub mirror — 5e.tools is behind Cloudflare)
const DATA_BASE_URL = "https://raw.githubusercontent.com/5etools-mirror-3/5etools-src/master/data";

// In-memory cache
let cache = {
  spells: null,
  monsters: null,
  monsterFluff: null,
  items: null,
  races: null,
  classes: null,
  rules: null,
  actions: null,
  feats: null,
};

/**
 * Clears the in-memory cache.
 */
function clearCache() {
  cache = {
    spells: null,
    monsters: null,
    monsterFluff: null,
    items: null,
    races: null,
    classes: null,
    rules: null,
    actions: null,
    feats: null,
  };
  logger.info("app:reference", "Memory cache cleared.");
}

/**
 * HTTP GET helper that returns response body as string.
 * Uses curl via child_process because 5e.tools is behind Cloudflare
 * which blocks Node.js's built-in http/https TLS fingerprint.
 */
function fetchUrl(url) {
  return new Promise((resolve, reject) => {
    const result = spawnSync("curl", [
      "-s",
      "-L",
      "--max-time", "30",
      "-H", "User-Agent: Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
      "-H", "Accept: application/json, text/plain, */*",
      url,
    ], { timeout: 35000, maxBuffer: 50 * 1024 * 1024, encoding: "utf8" });

    if (result.error) {
      reject(new Error(`Curl error: ${result.error.message}`));
      return;
    }
    if (result.status !== 0) {
      reject(new Error(`Curl exit code ${result.status} for ${url}: ${result.stderr?.substring(0, 200)}`));
      return;
    }
    resolve(result.stdout);
  });
}

/**
 * Returns a file-safe name from a URL path.
 */
function urlPathToFilename(urlPath) {
  return urlPath.replace(/^\/+/, "").replace(/[\/?]/g, "_");
}

/**
 * Ensures cache dir exists.
 */
function ensureCacheDir() {
  if (!fs.existsSync(CACHE_DIR)) {
    fs.mkdirSync(CACHE_DIR, { recursive: true });
  }
}

/**
 * Loads JSON data for a given 5e.tools URL path.
 * Tries: in-memory → disk cache → HTTP fetch.
 */
async function loadData(urlPath, dataKey) {
  const cacheFile = path.join(CACHE_DIR, urlPathToFilename(urlPath));
  const url = `${DATA_BASE_URL}${urlPath}`;

  // Try disk cache first
  if (fs.existsSync(cacheFile)) {
    try {
      const content = fs.readFileSync(cacheFile, "utf8");
      const data = JSON.parse(content);
      if (data && Array.isArray(data[dataKey])) {
        return data[dataKey];
      }
    } catch (err) {
      logger.warn("app:reference", `Cache read failed for ${cacheFile}: ${err.message}`);
    }
  }

  // Fetch from remote
  try {
    logger.info("app:reference", `Fetching ${url}...`);
    const body = await fetchUrl(url);
    ensureCacheDir();
    fs.writeFileSync(cacheFile, body, "utf8");
    const data = JSON.parse(body);
    if (data && Array.isArray(data[dataKey])) {
      return data[dataKey];
    }
    return [];
  } catch (err) {
    logger.error("app:reference", `Failed to fetch ${url}: ${err.message}`);
    return [];
  }
}

/**
 * Scan the cache directory for all bestiary/spell files and load/combine them.
 */
function loadAllFromCache(prefix, arrayKey) {
  const list = [];
  if (!fs.existsSync(CACHE_DIR)) return list;

  try {
    const files = fs.readdirSync(CACHE_DIR);
    for (const file of files) {
      if (!file.startsWith(prefix)) continue;
      if (!file.endsWith(".json")) continue;
      try {
        const content = fs.readFileSync(path.join(CACHE_DIR, file), "utf8");
        const data = JSON.parse(content);
        if (data && Array.isArray(data[arrayKey])) {
          list.push(...data[arrayKey]);
        }
      } catch (err) {
        logger.warn("app:reference", `Failed to parse cached file ${file}:`, { error: err.message });
      }
    }
  } catch (err) {
    logger.error("app:reference", `Cache directory read failed:`, { error: err.message });
  }
  return list;
}

/**
 * Attempts to load from a single cached JSON file.
 */
function loadSingleFromCache(filename, arrayKey) {
  const filePath = path.join(CACHE_DIR, filename);
  if (!fs.existsSync(filePath)) return [];
  try {
    const content = fs.readFileSync(filePath, "utf8");
    const data = JSON.parse(content);
    if (data && Array.isArray(data[arrayKey])) {
      return data[arrayKey];
    }
  } catch (err) {
    logger.warn("app:reference", `Failed to parse ${filePath}:`, { error: err.message });
  }
  return [];
}

// ---------------------------------------------------------------------------
// Lazy loaders — try disk cache first, then async fetch on miss
// ---------------------------------------------------------------------------
function getSpells() {
  if (cache.spells) return cache.spells;
  cache.spells = loadAllFromCache("spells_spells-", "spell");
  if (!cache.spells.length) {
    cache.spells = loadSingleFromCache("spells_spells-phb.json", "spell");
  }
  logger.info("app:reference", `Loaded ${cache.spells.length} spells from cache.`);
  return cache.spells;
}

function getMonsters() {
  if (cache.monsters) return cache.monsters;
  cache.monsters = loadAllFromCache("bestiary_bestiary-", "monster");
  if (!cache.monsters.length) {
    cache.monsters = loadSingleFromCache("bestiary_bestiary-mm.json", "monster");
  }
  logger.info("app:reference", `Loaded ${cache.monsters.length} monsters from cache.`);
  return cache.monsters;
}

function getMonsterFluff() {
  if (cache.monsterFluff) return cache.monsterFluff;
  cache.monsterFluff = loadAllFromCache("bestiary_fluff-bestiary-", "monsterFluff");
  if (!cache.monsterFluff.length) {
    cache.monsterFluff = loadSingleFromCache("bestiary_fluff-bestiary-mm.json", "monsterFluff");
  }
  logger.info("app:reference", `Loaded ${cache.monsterFluff.length} monster fluff entries from cache.`);
  return cache.monsterFluff;
}

function getItems() {
  if (cache.items) return cache.items;
  cache.items = loadSingleFromCache("items.json", "item");
  if (!cache.items.length) {
    cache.items = loadSingleFromCache("items.json", "item");
  }
  logger.info("app:reference", `Loaded ${cache.items.length} items from cache.`);
  return cache.items;
}

function getRaces() {
  if (cache.races) return cache.races;
  cache.races = loadSingleFromCache("races.json", "race");
  logger.info("app:reference", `Loaded ${cache.races.length} races from cache.`);
  return cache.races;
}

function getClasses() {
  if (cache.classes) return cache.classes;
  cache.classes = loadAllFromCache("class_class-", "class");
  if (!cache.classes.length) {
    cache.classes = loadSingleFromCache("class_class-barbarian.json", "class");
  }
  logger.info("app:reference", `Loaded ${cache.classes.length} classes from cache.`);
  return cache.classes;
}

function getRules() {
  if (cache.rules) return cache.rules;
  cache.rules = loadSingleFromCache("actions.json", "action");
  logger.info("app:reference", `Loaded ${cache.rules.length} rules/actions from cache.`);
  return cache.rules;
}

function getFeats() {
  if (cache.feats) return cache.feats;
  cache.feats = loadSingleFromCache("feats.json", "feat");
  if (!cache.feats.length) {
    cache.feats = loadSingleFromCache("feats.json", "feat");
  }
  logger.info("app:reference", `Loaded ${cache.feats.length} feats from cache.`);
  return cache.feats;
}

// ---------------------------------------------------------------------------
// Helpers (unchanged from original)
// ---------------------------------------------------------------------------
function normalizeSource(source) {
  return String(source || "").trim().toUpperCase();
}

function normalizeSourceList(sources = []) {
  if (!Array.isArray(sources)) return [];
  return sources.map(normalizeSource).filter(Boolean);
}

function applySourceFilter(dataset, sources = []) {
  const allowedSources = normalizeSourceList(sources);
  if (allowedSources.length === 0) return dataset;
  const allowed = new Set(allowedSources);
  return dataset.filter((item) => allowed.has(normalizeSource(item?.source)));
}

function summarizeItem(item, category) {
  const base = { name: item.name, source: item.source };
  switch (category) {
    case "spells":
      return { ...base, level: item.level, school: item.school, time: item.time, range: item.range, duration: item.duration };
    case "monsters":
      return { ...base, cr: item.cr, hp: item.hp ? { average: item.hp.average, formula: item.hp.formula } : undefined, ac: item.ac, size: item.size, type: item.type };
    case "items":
      return { ...base, rarity: item.rarity, type: item.type, weight: item.weight, value: item.value };
    case "feats":
      return { ...base, prerequisite: item.prerequisite };
    default:
      return base;
  }
}

function getDataset(category) {
  switch (category.toLowerCase()) {
    case "spells":   return getSpells();
    case "monsters": return getMonsters();
    case "items":    return getItems();
    case "races":    return getRaces();
    case "classes":  return getClasses();
    case "rules":    return getRules();
    case "feats":    return getFeats();
    default:         return [];
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------
function search(category, query = "", limit = 50, options = {}) {
  const normalizedCategory = String(category || "").toLowerCase();
  let dataset = applySourceFilter(getDataset(normalizedCategory), options.sources);
  const cleanQuery = query.trim().toLowerCase();
  if (cleanQuery) {
    dataset = dataset.filter((item) => item && item.name && item.name.toLowerCase().includes(cleanQuery));
  }
  return dataset.slice(0, limit).map((item) => options.summary === false ? item : summarizeItem(item, normalizedCategory));
}

function getByName(category, name, source = "", options = {}) {
  const normalizedCategory = String(category || "").toLowerCase();
  const cleanName = String(name || "").trim().toLowerCase();
  const cleanSource = normalizeSource(source);
  if (!cleanName) return null;
  const dataset = applySourceFilter(getDataset(normalizedCategory), options.sources);
  return dataset.find((item) => {
    if (!item?.name || item.name.toLowerCase() !== cleanName) return false;
    return !cleanSource || normalizeSource(item.source) === cleanSource;
  }) || null;
}

function hasUsableFluff(fluff) {
  return Boolean(fluff && Array.isArray(fluff.entries) && fluff.entries.length);
}

function getMonsterFluffByName(name, source = "", options = {}) {
  const cleanName = String(name || "").trim().toLowerCase();
  const cleanSource = normalizeSource(source);
  if (!cleanName) return null;
  const dataset = applySourceFilter(getMonsterFluff(), options.sources);
  const sourceMatches = dataset.filter((item) => {
    if (!item?.name) return false;
    return !cleanSource || normalizeSource(item.source) === cleanSource;
  });
  const exact = sourceMatches.find((item) => item.name.toLowerCase() === cleanName);
  if (hasUsableFluff(exact)) return exact;
  const words = cleanName.split(/\s+/).filter(Boolean);
  const familyCandidates = [];
  if (words.length) familyCandidates.push(`${words[0]}s`);
  if (words.length > 1) familyCandidates.push(`${words.slice(0, -1).join(" ")}s`);
  return sourceMatches.find((item) => (hasUsableFluff(item) && familyCandidates.includes(item.name.toLowerCase()))) || exact || null;
}

function listAvailableSources(category) {
  const sourceSet = new Set();
  const categories = category ? [category] : ["spells", "monsters", "items", "races", "classes", "rules", "feats"];
  for (const cat of categories) {
    for (const item of getDataset(cat)) {
      const src = normalizeSource(item?.source);
      if (src) sourceSet.add(src);
    }
  }
  return Array.from(sourceSet).sort();
}

module.exports = {
  search,
  getByName,
  getMonsterFluffByName,
  listAvailableSources,
  clearCache,
  loadData, // Exported for on-demand cache population
};

// =============================================================================
// Tablecast  5etools HTTP Cache Manager
// Fetches D&D 5e reference data from GitHub raw mirror and caches to disk.
// (5e.tools itself is behind Cloudflare JS challenge, so we use the GitHub
// mirror at 5etools-mirror-3 which has the exact same data.)
// =============================================================================
"use strict";

const fs = require("fs");
const path = require("path");
const { spawnSync } = require("child_process");

// Cache directory — resolves to server/uploads/5etools-cache/
const CACHE_DIR = path.resolve(__dirname, "../../uploads/5etools-cache");

// Base URL for 5etools raw data (GitHub mirror — 5e.tools is behind Cloudflare)
const DATA_BASE_URL = "https://raw.githubusercontent.com/5etools-mirror-3/5etools-src/master/data";

// Mapping of category to remote JSON paths
const DATA_FILES = {
  spells:   "/spells/spells-phb.json",
  monsters: "/bestiary/bestiary-mm.json",
  items:    "/items.json",
  races:    "/races.json",
  classes:  "/class/class-barbarian.json",
  feats:    "/feats.json",
};

// Additional spell/monster/class source files (discovered at sync time)
const ADDITIONAL_SOURCES = [
  "/spells/spells-xge.json",
  "/spells/spells-tce.json",
  "/spells/spells-ftd.json",
  "/spells/spells-scc.json",
  "/spells/spells-bmt.json",
  "/spells/spells-ggr.json",
  "/spells/spells-idrotf.json",
  "/spells/spells-ai.json",
  "/bestiary/bestiary-xmm.json",
  "/bestiary/bestiary-ftd.json",
  "/bestiary/bestiary-tce.json",
  "/bestiary/bestiary-bmt.json",
  "/bestiary/bestiary-scc.json",
  "/bestiary/bestiary-ggr.json",
  "/bestiary/bestiary-mot.json",
  "/bestiary/fluff-bestiary-mm.json",
  "/bestiary/fluff-bestiary-xmm.json",
  "/class/class-bard.json",
  "/class/class-cleric.json",
  "/class/class-druid.json",
  "/class/class-fighter.json",
  "/class/class-monk.json",
  "/class/class-paladin.json",
  "/class/class-ranger.json",
  "/class/class-rogue.json",
  "/class/class-sorcerer.json",
  "/class/class-warlock.json",
  "/class/class-wizard.json",
  "/class/class-artificer.json",
  "/actions.json",
];

// In-memory sync state
const syncState = {
  isSyncing: false,
  status: "idle", // "idle", "syncing", "success", "error"
  progress: "Idle",
  logs: [],
  cachedBytes: 0,
  cacheFileCount: 0,
};

/**
 * Log message helper.
 */
function log(message, type = "info") {
  const timestamp = new Date().toLocaleTimeString();
  const logLine = `[${timestamp}] [${type.toUpperCase()}] ${message}`;
  console.log(`[ReferenceSync] ${logLine}`);
  syncState.logs.push(logLine);
  if (syncState.logs.length > 500) {
    syncState.logs.shift();
  }
}

/**
 * HTTP GET helper that returns response body as string.
 * Uses curl via child_process to fetch from GitHub (raw.githubusercontent.com).
 * Curl is also used as a backup strategy if we ever need to bypass Cloudflare
 * on the main 5e.tools site.
 */
function fetchUrl(url) {
  return new Promise((resolve, reject) => {
    const result = spawnSync("curl", [
      "-s",
      "-L",
      "--max-time", "30",
      "-H", "User-Agent: Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
      "-H", "Accept: application/json, text/plain, */*",
      url,
    ], { timeout: 35000, maxBuffer: 50 * 1024 * 1024, encoding: "utf8" });

    if (result.error) {
      reject(new Error(`Curl error: ${result.error.message}`));
      return;
    }
    if (result.status !== 0) {
      reject(new Error(`Curl exit code ${result.status} for ${url}: ${result.stderr?.substring(0, 200)}`));
      return;
    }
    resolve(result.stdout);
  });
}

/**
 * Ensures the cache directory exists.
 */
function ensureCacheDir() {
  if (!fs.existsSync(CACHE_DIR)) {
    fs.mkdirSync(CACHE_DIR, { recursive: true });
    log(`Created cache directory: ${CACHE_DIR}`);
  }
}

/**
 * Returns a file-safe name from a URL path.
 */
function urlPathToFilename(urlPath) {
  return urlPath.replace(/^\/+/, "").replace(/[\/?]/g, "_");
}

/**
 * Returns full local path for a cached file.
 */
function getCacheFilePath(urlPath) {
  return path.join(CACHE_DIR, urlPathToFilename(urlPath));
}

/**
 * Scans the cache directory and computes total size.
 */
function scanCache() {
  if (!fs.existsSync(CACHE_DIR)) {
    syncState.cachedBytes = 0;
    syncState.cacheFileCount = 0;
    return;
  }
  try {
    const files = fs.readdirSync(CACHE_DIR);
    syncState.cacheFileCount = files.length;
    syncState.cachedBytes = files.reduce((total, file) => {
      const filePath = path.join(CACHE_DIR, file);
      try {
        return total + fs.statSync(filePath).size;
      } catch { return total; }
    }, 0);
  } catch (err) {
    log(`Cache scan failed: ${err.message}`, "error");
  }
}

/**
 * Returns current sync status.
 */
function getStatus() {
  scanCache();
  return { ...syncState };
}

/**
 * Fetches a data file from 5e.tools and caches it to disk.
 */
async function fetchAndCache(urlPath) {
  const url = `${DATA_BASE_URL}${urlPath}`;
  const cacheFile = getCacheFilePath(urlPath);
  const label = urlPath.split("/").pop();

  try {
    log(`Fetching ${label} from ${url}...`);
    const body = await fetchUrl(url);

    // Validate JSON before caching
    try { JSON.parse(body); } catch (e) {
      throw new Error(`Invalid JSON for ${label}: ${e.message}`);
    }

    fs.writeFileSync(cacheFile, body, "utf8");
    log(`Cached ${label} (${(Buffer.byteLength(body) / 1024).toFixed(1)} KB)`);
    return true;
  } catch (err) {
    log(`Failed to fetch ${label}: ${err.message}`, "error");
    return false;
  }
}

/**
 * Orchestrates fetching data files in the background.
 */
async function sync() {
  if (syncState.isSyncing) {
    log("Sync already in progress. Ignoring request.", "warn");
    return;
  }

  syncState.isSyncing = true;
  syncState.status = "syncing";
  syncState.logs = [];
  log("Starting 5etools data cache refresh...");

  ensureCacheDir();

  try {
    // Collect all URLs to fetch
    const allSources = new Set(Object.values(DATA_FILES));
    for (const src of ADDITIONAL_SOURCES) {
      allSources.add(src);
    }

    const urls = Array.from(allSources);
    let successCount = 0;
    let failCount = 0;

    for (let i = 0; i < urls.length; i++) {
      const urlPath = urls[i];
      syncState.progress = `Fetching ${i + 1}/${urls.length}: ${urlPath.split("/").pop()}...`;

      const ok = await fetchAndCache(urlPath);
      if (ok) successCount++;
      else failCount++;
    }

    scanCache();
    syncState.progress = `Cache refresh complete: ${successCount} OK, ${failCount} failed, ${syncState.cacheFileCount} files (${(syncState.cachedBytes / 1024 / 1024).toFixed(1)} MB)`;
    syncState.status = failCount > 0 ? "error" : "success";
    log(`Sync finished. ${successCount} OK, ${failCount} failed. Total cache: ${syncState.cacheFileCount} files, ${(syncState.cachedBytes / 1024 / 1024).toFixed(1)} MB`);
  } catch (err) {
    syncState.progress = `Sync failed: ${err.message}`;
    syncState.status = "error";
    log(`Sync failed: ${err.message}`, "error");
  } finally {
    syncState.isSyncing = false;
  }
}

/**
 * Clears the entire disk cache.
 */
function clearDiskCache() {
  if (!fs.existsSync(CACHE_DIR)) return;
  try {
    const files = fs.readdirSync(CACHE_DIR);
    for (const file of files) {
      fs.unlinkSync(path.join(CACHE_DIR, file));
    }
    syncState.cachedBytes = 0;
    syncState.cacheFileCount = 0;
    log("Disk cache cleared.");
  } catch (err) {
    log(`Failed to clear disk cache: ${err.message}`, "error");
  }
}

/**
 * Returns the cache directory path for use by referenceSearch.
 */
function getCacheDir() {
  return CACHE_DIR;
}

module.exports = {
  getStatus,
  sync,
  clearDiskCache,
  getCacheDir,
  DATA_BASE_URL,
};

